-- Flashcard topics & cards
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-ci-fc-1.1', '1.1 Ethnic Tensions in Rwanda: Hutu and Tutsi Relations', '#C4A36A', 'P1-CI', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.1', 'Hutu', 'Majority ethnic group in Rwanda (~85%); historically farmers; held power from 1962 independence until 1994 genocide.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.1', 'Tutsi', 'Minority ethnic group (~14%); historically associated with cattle-keeping and pre-colonial aristocracy; targeted in the 1994 genocide.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.1', 'Twa', 'Smallest ethnic group (~1%); indigenous forest-dwelling people; often marginalised in Rwandan politics. Colonial manipulation of Belgian colonisers institutionalised ethnicity Hutu-Tutsi divisions through identity cards (1933), racial classification, and preferential treatment of Tutsis, then later switched to supporting Hutus.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.1', 'Hutu Revolution (1959--61)', 'Hutu uprising against Tutsi monarchy; thousands of Tutsis killed or exiled; established Hutu-dominated republic.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.1', 'Identity cards', 'Introduced by Belgians in 1933; classified all Rwandans as Hutu, Tutsi, or Twa; used during the genocide to identify victims. ☑', 5);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-ci-fc-1.2', '1.2 Creation of the Hutu Power Movement and the Interahamwe', '#C4A36A', 'P1-CI', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.2', 'Hutu Power', 'Extremist political ideology promoting Hutu supremacy; sought the elimination of Tutsi ''threat''; key driver of the genocide. Interahamwe (''Those who Hutu militia group, youth wing of the attack together'') MRND party; trained and armed by the government; primary perpetrators of the genocide. Impuzamugambi (''Those who Militia linked to the Coalition for the have the same goal'') Defence of the Republic (CDR); another key perpetrator group in the genocide. Hutu Ten Commandments Published in Kangura newspaper; (1990) portrayed all Tutsis as enemies; called for Hutu vigilance and separation from Tutsis. MRND (National Revolutionary President Habyarimana''s ruling party; Movement for Development) created the Interahamwe militias and promoted Hutu Power ideology.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.2', 'Akazu (''Little House'')', 'Inner circle of Hutu Power extremists around Habyarimana and his wife; believed to have planned and orchestrated the genocide. ☑', 2);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-ci-fc-1.3', '1.3 Role of the Media in Rwanda', '#C4A36A', 'P1-CI', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.3', 'Kangura newspaper', 'Hutu Power newspaper that published the Hutu Ten Commandments and virulent anti-Tutsi propaganda.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.3', '''Cut down the tall trees''', 'RTLM coded language instructing Hutus to kill Tutsis; ''tall trees'' was a reference to Tutsis, who were stereotypically portrayed as taller.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.3', '''Cockroaches'' (Inyenzi)', 'Dehumanising term used by Hutu Power media to describe Tutsis; dehumanisation was a key step toward genocide.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.3', 'Propaganda techniques', 'Dehumanisation, fear-mongering, conspiracy theories about Tutsi plots, glorification of Hutu identity, calls to ''self-defence''. ☑', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-ci-fc-1.4', '1.4 Other Causes: Economic Situation and Colonial Legacy', '#C4A36A', 'P1-CI', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.4', 'Population pressure', 'Rwanda was one of Africa''s most densely populated countries; competition for land intensified ethnic tensions.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.4', 'Colonial legacy', 'Belgian divide-and-rule policies created the framework of ethnic hatred; post-colonial Hutu governments continued ethnic discrimination against Tutsis. Habyarimana regime One-party Hutu-dominated state; (1973--94) increasing corruption, economic decline, and resistance to power-sharing fuelled extremism. ☑', 2);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-ci-fc-1.5', '1.5 Rwandan Civil War (1990--93) and Assassination of Habyarimana (1994)', '#C4A36A', 'P1-CI', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.5', 'RPF invasion (October 1990)', 'RPF attack from Uganda; triggered increased repression of Tutsis inside Rwanda and radicalisation of Hutu Power. Arusha Accords (August Peace agreement between Habyarimana 1993) government and RPF; provided for power-sharing and integration of RPF into the army; opposed by Hutu extremists. Assassination of Habyarimana President''s plane shot down over (6 April 1994) Kigali airport; also killed Burundian President Ntaryamira; served as the trigger for the genocide.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.5', 'Trigger of the genocide', 'Within hours of Habyarimana''s assassination, roadblocks were set up and systematic killing of Tutsis and moderate Hutus began. ☑', 2);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-ci-fc-1.6', '1.6 Actions of the RPF and Rwandan Government; Nature of the Genocide', '#C4A36A', 'P1-CI', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.6', 'Speed of the genocide', 'Approximately 800,000--1,000,000 Tutsis and moderate Hutus killed in approximately 100 days (April--July 1994).', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.6', 'Methods of killing', 'Primarily machetes, clubs, and other improvised weapons; mass killings at churches, schools, and roadblocks; neighbours killed neighbours.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.6', 'War rape', 'Systematic sexual violence against Tutsi women as a weapon of genocide; estimated 250,000--500,000 women raped.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.6', 'Moderate Hutus targeted', 'Hutus who opposed the genocide or sheltered Tutsis were also killed; PM Agathe Uwilingiyimana assassinated on 7 April.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.6', 'RPF advance', 'RPF forces fought their way from the northeast; gradually took control of Rwanda; ended the genocide by capturing Kigali in July 1994.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.6', 'Paul Kagame', 'RPF military commander; led the forces that ended the genocide; became president of Rwanda (2000--present). ☑', 6);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-ci-fc-1.7', '1.7 Response of the International Community; UNAMIR; Reasons for', '#C4A36A', 'P1-CI', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.7', 'General Roméo Dallaire', 'Canadian commander of UNAMIR; warned of genocide in January 1994 ''genocide fax'' but was denied permission to act.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.7', 'Genocide fax (January 1994)', 'Dallaire''s warning to UN headquarters about weapons caches and planned extermination of Tutsis; UN refused to authorise action.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.7', 'US reluctance', 'After Somalia debacle (1993), the US avoided involvement; Clinton administration refused to use the word ''genocide'' to avoid legal obligation to intervene.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.7', 'Belgian withdrawal', 'After 10 Belgian peacekeepers were murdered on 7 April, Belgium withdrew its forces from UNAMIR, fatally weakening the mission. Opération Turquoise French military intervention; (June--August 1994) ostensibly humanitarian but controversial; France had previously supported the Habyarimana government. Security Council Resolution Reduced UNAMIR from 2,500 to 270 troops 912 at the height of the genocide (21 April 1994). ☑', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-ci-fc-1.8', '1.8 Social Impact: Refugee Crisis; Justice and Reconciliation', '#C4A36A', 'P1-CI', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.8', 'Refugee crisis (1994)', 'Over 2 million Hutus (including génocidaires) fled to neighbouring countries, especially eastern Zaire (DRC); refugee camps became bases for militants.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.8', 'Gacaca courts', 'Community-based justice system used to try hundreds of thousands of genocide suspects; aimed to combine justice with reconciliation. International Criminal UN tribunal established in Arusha, Tribunal for Rwanda (ICTR) Tanzania (1994); tried senior leaders for genocide; convicted key figures including PM Jean Kambanda.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.8', 'Social trauma', 'Hundreds of thousands of orphans, widows, survivors of sexual violence; destroyed social fabric; long-term psychological impact.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.8', 'Reconciliation efforts', 'Government promoted national unity; removed ethnic identity from ID cards; emphasised ''Rwandan'' identity over ethnic labels. ☑', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-ci-fc-1.9', '1.9 Political and Economic Impact; RPF-Led Governments; Continued', '#C4A36A', 'P1-CI', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.9', 'RPF government', 'Paul Kagame''s RPF-led government has ruled Rwanda since 1994; credited with stability and economic growth but criticised for authoritarianism.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-1.9', 'First Congo War (1996--97)', 'Rwanda (and Uganda) invaded Zaire to dismantle Hutu militia camps and overthrow Mobutu; installed Laurent-Désiré Kabila as president. Second Congo War Rwandan forces intervened again in DRC; (1998--2003) deadliest conflict since WWII; estimated 5.4 million excess deaths. Rwandan economic Post-genocide Rwanda achieved development significant economic growth, poverty reduction, and development under Kagame; but at the cost of political freedom. International Criminal Court Established by the Rome Statute (1998); (ICC) permanent court to prosecute genocide, war crimes, and crimes against humanity; inspired partly by Rwanda and Yugoslavia. ☑', 2);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-ci-fc-2.1', '2.1 Ethnic Tensions Between Serbs and Kosovar Albanians', '#C4A36A', 'P1-CI', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.1', 'Kosovo', 'Province of Serbia; approximately 90% ethnic Albanian population; considered sacred by Serbs due to the 1389 Battle of Kosovo.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.1', 'Battle of Kosovo (1389)', 'Medieval battle between Serbs and Ottomans; foundation of Serbian national mythology; used to justify Serbian claims to Kosovo.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.1', 'Kosovar Albanians', 'Ethnic Albanian majority population of Kosovo; predominantly Muslim; sought autonomy or independence from Serbia.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.1', '1974 Yugoslav Constitution', 'Granted Kosovo significant autonomy within Yugoslavia; had its own government, assembly, and representation in federal institutions.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.1', 'Rising Albanian nationalism', 'Growing demands for Kosovo to become a full republic within Yugoslavia, not just an autonomous province of Serbia.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.1', 'Serbian minority in Kosovo', '~10% of Kosovo''s population; viewed with increasing resentment by some Kosovar Albanians; their perceived mistreatment was exploited by Serb nationalists. ☑', 6);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-ci-fc-2.2', '2.2 Political Causes: Constitutional Reforms (1989--94); Repression', '#C4A36A', 'P1-CI', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.2', 'Slobodan Milosevic', 'Serbian and Yugoslav president; revoked Kosovo''s autonomy in 1989; used Serbian nationalism to consolidate power; indicted for war crimes. Revocation of Kosovo''s Milosevic stripped Kosovo of its autonomy (1989) autonomous status; imposed direct Serbian rule; Albanian language and institutions suppressed. Milosevic''s Gazimestan Speech at the 600th anniversary of the speech (1989) Battle of Kosovo; widely interpreted as promoting Serbian nationalism and warning of future conflicts. Apartheid-like system in After 1989: Albanians dismissed from Kosovo public sector jobs, Albanian-language schools and university closed, health care restricted.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.2', 'Ibrahim Rugova', 'Leader of the Democratic League of Kosovo (LDK); advocated peaceful, non-violent resistance to Serbian rule; ''Gandhi of the Balkans''.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.2', 'Parallel institutions', 'Kosovar Albanians created shadow government, schools, and healthcare system to operate independently of Serbian state. ☑', 3);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-ci-fc-2.3', '2.3 Role of Ibrahim Rugova and Non-Violent Resistance', '#C4A36A', 'P1-CI', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.3', 'Ibrahim Rugova (1944--2006)', 'Leader of the LDK; declared Kosovo independent in 1991 (unrecognised); elected president of shadow republic; advocated exclusively peaceful methods. Democratic League of Kosovo Major Kosovar Albanian political party; (LDK) led non-violent resistance movement under Rugova.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.3', 'Shadow Republic of Kosovo', 'Parallel state structures including schools, healthcare, taxation; maintained Albanian civil society under Serbian repression.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.3', 'Dayton Accords (1995)', 'Peace agreement ending the Bosnian War; Kosovo was not addressed, leading to Kosovar Albanian disillusionment with peaceful methods. Failure of non-violence to Despite years of peaceful resistance, gain international support the international community largely ignored Kosovo''s situation; contributed to the rise of the KLA. ☑', 3);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-ci-fc-2.4', '2.4 Kosovo Liberation Army (KLA) and Serbian Response', '#C4A36A', 'P1-CI', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.4', 'KLA tactics', 'Guerrilla warfare, attacks on Serbian police and officials; initially small but gained mass support after Serbian reprisals against civilians.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.4', 'Serbian counter-insurgency', 'Disproportionate Serbian military and police operations against Albanian civilians; destroyed villages; created massive displacement.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.4', 'Drenica massacres (1998)', 'Serbian security forces killed dozens of Albanian civilians in the Drenica region; galvanised international attention.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.4', 'Albanian arms crisis (1997)', 'Collapse of pyramid schemes in Albania led to chaos and looting of military arsenals; weapons flowed to the KLA. ☑', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-ci-fc-2.5', '2.5 Ethnic Cleansing and Crimes Against Humanity; Račak Massacre', '#C4A36A', 'P1-CI', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.5', 'Ethnic cleansing in Kosovo', 'Systematic Serbian campaign to expel Kosovar Albanians; destruction of villages, mass displacement, killings, sexual violence. Račak massacre (15 January Serbian security forces killed 45 1999) Albanian civilians in the village of Račak; became a key catalyst for NATO intervention.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.5', 'William Walker', 'US diplomat and OSCE verification mission head who declared Račak a ''crime against humanity''; galvanised international response. Rambouillet negotiations Failed peace talks; Serbia refused to (Feb--March 1999) accept NATO peacekeepers in Kosovo; provided the political justification for NATO bombing.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.5', 'Operation Horseshoe', 'Alleged Serbian plan for the systematic expulsion of Kosovar Albanians; scale of ethnic cleansing accelerated after NATO bombing began. ☑', 3);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-ci-fc-2.6', '2.6 Response of the International Community; NATO Bombing; KFOR', '#C4A36A', 'P1-CI', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.6', 'KFOR (Kosovo Force)', 'NATO-led peacekeeping force deployed to Kosovo after the war; maintained security and supervised Serbian withdrawal. UN Security Council Ended the conflict; placed Kosovo under Resolution 1244 (June 1999) UN administration (UNMIK); authorised KFOR deployment; maintained Serbian sovereignty in theory.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.6', 'UNMIK', 'United Nations Interim Administration Mission in Kosovo; governed Kosovo from 1999 until Kosovo''s independence declaration in 2008. ☑', 2);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-ci-fc-2.7', '2.7 Social and Economic Consequences; Refugee Crisis; Damage to', '#C4A36A', 'P1-CI', 16);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.7', 'Kosovo refugee crisis', 'Nearly 1 million Kosovar Albanians displaced during the conflict; mostly to Albania, Macedonia, and Montenegro.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.7', 'Return of refugees', 'After NATO intervention, most Albanian refugees returned; but approximately 200,000 Serbs and Roma fled Kosovo.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.7', 'Infrastructure destruction', 'Extensive damage to homes, schools, hospitals, and infrastructure from both Serbian forces and NATO bombing.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.7', 'Economic devastation', 'Kosovo''s already weak economy further damaged; high unemployment; dependence on international aid.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.7', 'Reverse ethnic cleansing', 'After the war, Kosovar Albanians attacked remaining Serbian communities; destruction of Serbian churches and cultural sites. ☑', 5);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-ci-fc-2.8', '2.8 Political Impact in Kosovo; Election of Ibrahim Rugova (2002)', '#C4A36A', 'P1-CI', 17);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.8', 'UNMIK governance', 'UN administration governed Kosovo from 1999; gradually transferred power to local institutions.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.8', 'Kosovo elections (2001--02)', 'First democratic elections under UNMIK; Ibrahim Rugova elected president of Kosovo in 2002. Rugova as president Led Kosovo through early years of (2002--06) self-governance; continued to advocate for independence through peaceful means.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.8', 'Kosovo''s status question', 'Contested: Kosovar Albanians sought full independence; Serbia insisted Kosovo remained its province; resolved by unilateral declaration in 2008. Standards before status International community required Kosovo policy to meet governance standards before its final political status would be determined. ☑', 3);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-ci-fc-2.9', '2.9 ICTY; Indictment of Milosevic; International Reaction', '#C4A36A', 'P1-CI', 18);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-ci-fc-2.9', 'Milosevic trial', 'Began in 2002; Milosevic defended himself; died in custody in 2006 before a verdict was reached. Fall of Milosevic (October Popular uprising (Bulldozer Revolution) 2000) overthrew Milosevic; he was later extradited to The Hague. Significance of ICTY for Established precedents for prosecuting international justice heads of state; demonstrated accountability for war crimes; but also criticised for being slow and selective. ☑', 1);

-- MCQ questions
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-001', '1.1 Ethnic Tensions in Rwanda: Hutu and Tutsi Relations', 'SL/HL', 'P1-CI', 'The Belgian colonial administration deepened Hutu-Tutsi divisions by:', 'Treating all ethnic groups equally', 'Introducing identity cards and racial classification that institutionalised ethnic categories', 'Abolishing all ethnic distinctions', 'Allowing democratic self-governance', 1, 'See mark scheme for detailed explanation.', 2);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-002', '1.1 Ethnic Tensions in Rwanda: Hutu and Tutsi Relations', 'SL/HL', 'P1-CI', 'The Hutu Revolution (1959--61) resulted in:', 'A multi-ethnic democracy', 'The overthrow of Tutsi monarchy and mass exile of Tutsis', 'Belgian recolonisation', 'A Tutsi-dominated republic', 1, 'See mark scheme for detailed explanation.', 3);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-003', '1.1 Ethnic Tensions in Rwanda: Hutu and Tutsi Relations', 'SL/HL', 'P1-CI', 'Which group constituted the majority of Rwanda''s population?', 'Tutsi', 'Twa', 'Hutu', 'Belgian settlers', 2, 'See mark scheme for detailed explanation.', 4);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-004', '1.1 Ethnic Tensions in Rwanda: Hutu and Tutsi Relations', 'SL/HL', 'P1-CI', 'Identity cards were significant in the genocide because:', 'They proved Rwandan citizenship', 'They were used to identify and target Tutsi victims', 'They were voluntary documents', 'They showed educational qualifications', 1, 'See mark scheme for detailed explanation.', 5);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-005', '1.2 Creation of the Hutu Power Movement and the Interahamwe', 'SL/HL', 'P1-CI', 'The Interahamwe were:', 'A Tutsi rebel group', 'A Hutu militia trained and armed by the government to carry out killings', 'A United Nations peacekeeping force', 'A Belgian colonial police force', 1, 'See mark scheme for detailed explanation.', 6);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-006', '1.2 Creation of the Hutu Power Movement and the Interahamwe', 'SL/HL', 'P1-CI', 'The Hutu Ten Commandments (1990) were significant because they:', 'Called for peace between Hutus and Tutsis', 'Portrayed all Tutsis as enemies and called for Hutu separation from them', 'Were part of the Arusha Accords', 'Were published by the United Nations', 1, 'See mark scheme for detailed explanation.', 7);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-007', '1.2 Creation of the Hutu Power Movement and the Interahamwe', 'SL/HL', 'P1-CI', 'The Akazu were:', 'International mediators', 'An inner circle of Hutu Power extremists believed to have planned the genocide', 'Moderate Hutu politicians', 'Tutsi military leaders', 1, 'See mark scheme for detailed explanation.', 8);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-008', '1.3 Role of the Media in Rwanda', 'SL/HL', 'P1-CI', 'RTLM was significant during the genocide because it:', 'Called for peace and reconciliation', 'Broadcast hate propaganda, identified Tutsi targets, and coordinated killings', 'Was a Tutsi-controlled media outlet', 'Was operated by the United Nations', 1, 'See mark scheme for detailed explanation.', 9);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-009', '1.3 Role of the Media in Rwanda', 'SL/HL', 'P1-CI', 'Calling Tutsis ''cockroaches'' (Inyenzi) was an example of:', 'Cultural respect', 'Dehumanisation designed to make killing psychologically easier', 'Accurate biological classification', 'A term of endearment', 1, 'See mark scheme for detailed explanation.', 10);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-010', '1.3 Role of the Media in Rwanda', 'SL/HL', 'P1-CI', 'The role of media in the Rwandan genocide demonstrates that:', 'Media has no influence on violence', 'Propaganda and media can be powerful tools for inciting and coordinating mass violence', 'Only print media can influence public opinion', 'Radio technology was not available in Rwanda', 1, 'See mark scheme for detailed explanation.', 11);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-011', '1.4 Other Causes: Economic Situation and Colonial Legacy', 'SL/HL', 'P1-CI', 'The collapse of coffee prices in the late 1980s contributed to the genocide by:', 'Making Rwanda wealthier', 'Causing economic crisis and social frustration that elites channelled into ethnic hatred', 'Improving relations between Hutus and Tutsis', 'Leading to increased foreign investment', 1, 'See mark scheme for detailed explanation.', 12);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-012', '1.4 Other Causes: Economic Situation and Colonial Legacy', 'SL/HL', 'P1-CI', 'The colonial legacy contributed to the genocide primarily through:', 'Providing economic development', 'Institutionalising ethnic divisions that post-colonial governments exploited', 'Promoting multi-ethnic democracy', 'Withdrawing all colonial infrastructure', 1, 'See mark scheme for detailed explanation.', 13);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-013', '1.5 Rwandan Civil War (1990--93) and Assassination of Habyarimana (1994)', 'SL/HL', 'P1-CI', 'The Arusha Accords (1993) were significant because they:', 'Ended the genocide', 'Proposed power-sharing between the Hutu government and RPF, which Hutu extremists opposed', 'Were rejected by the RPF', 'Were imposed by France', 1, 'See mark scheme for detailed explanation.', 14);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-014', '1.5 Rwandan Civil War (1990--93) and Assassination of Habyarimana (1994)', 'SL/HL', 'P1-CI', 'The assassination of Habyarimana (6 April 1994) was significant because:', 'It ended the civil war peacefully', 'It served as the immediate trigger for the genocide', 'It was carried out by the United Nations', 'It led to democratic elections', 1, 'See mark scheme for detailed explanation.', 15);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-015', '1.5 Rwandan Civil War (1990--93) and Assassination of Habyarimana (1994)', 'SL/HL', 'P1-CI', 'The RPF invasion of 1990 contributed to the genocide by:', 'Bringing peace to Rwanda', 'Increasing Hutu extremist fear and hatred of Tutsis', 'Establishing a Tutsi government immediately', 'Ending colonial rule', 1, 'See mark scheme for detailed explanation.', 16);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-016', '1.6 Actions of the RPF and Rwandan Government; Nature of the Genocide', 'SL/HL', 'P1-CI', 'The Rwandan genocide killed approximately:', '10,000 people', '100,000 people', '800,000--1,000,000 people', '5 million people', 2, 'See mark scheme for detailed explanation.', 17);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-017', '1.6 Actions of the RPF and Rwandan Government; Nature of the Genocide', 'SL/HL', 'P1-CI', 'The genocide was primarily carried out using:', 'Advanced military weapons', 'Nuclear weapons', 'Machetes, clubs, and improvised weapons with mass participation', 'Air strikes', 2, 'See mark scheme for detailed explanation.', 18);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-018', '1.6 Actions of the RPF and Rwandan Government; Nature of the Genocide', 'SL/HL', 'P1-CI', 'The genocide ended primarily because:', 'The UN sent a large peacekeeping force', 'The Interahamwe surrendered voluntarily', 'The RPF military advance captured Kigali in July 1994', 'France invaded Rwanda', 2, 'See mark scheme for detailed explanation.', 19);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-019', '1.7 Response of the International Community; UNAMIR; Reasons for', 'SL/HL', 'P1-CI', 'Dallaire''s ''genocide fax'' (January 1994) was significant because:', 'It led to immediate UN intervention', 'It warned of planned genocide but was ignored by UN headquarters', 'It called for the withdrawal of UN forces', 'It was sent after the genocide began', 1, 'See mark scheme for detailed explanation.', 20);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-020', '1.7 Response of the International Community; UNAMIR; Reasons for', 'SL/HL', 'P1-CI', 'The UN Security Council reduced UNAMIR forces during the genocide because:', 'The genocide had ended', 'Member states were unwilling to risk troops; the Belgian withdrawal after peacekeepers were killed prompted the reduction', 'Rwanda requested it', 'The RPF controlled the country', 1, 'See mark scheme for detailed explanation.', 21);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-021', '1.7 Response of the International Community; UNAMIR; Reasons for', 'SL/HL', 'P1-CI', 'The US avoided using the word ''genocide'' during the crisis because:', 'There was no evidence of genocide occurring', 'Using the term would create a legal obligation under the Genocide Convention to intervene', 'The US supported the Hutu government', 'It was a translation error', 1, 'See mark scheme for detailed explanation.', 22);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-022', '1.7 Response of the International Community; UNAMIR; Reasons for', 'SL/HL', 'P1-CI', 'Opération Turquoise was controversial because:', 'It was a successful humanitarian mission with no complications', 'France had previously supported the Habyarimana government, raising questions about its motives', 'It was carried out by the RPF', 'It prevented all civilian casualties', 1, 'See mark scheme for detailed explanation.', 23);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-023', '1.8 Social Impact: Refugee Crisis; Justice and Reconciliation', 'SL/HL', 'P1-CI', 'The Gacaca courts were:', 'International criminal tribunals', 'Community-based courts used to try genocide suspects and promote reconciliation', 'Military courts', 'Colonial-era courts restored by the government', 1, 'See mark scheme for detailed explanation.', 24);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-024', '1.8 Social Impact: Refugee Crisis; Justice and Reconciliation', 'SL/HL', 'P1-CI', 'The ICTR was significant because:', 'It was the first international tribunal to convict a head of government (PM Kambanda) for genocide', 'It tried all genocide suspects in Rwanda', 'It was based in Kigali', 'It was established before the genocide began', 0, 'See mark scheme for detailed explanation.', 25);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-025', '1.9 Political and Economic Impact; RPF-Led Governments; Continued', 'SL/HL', 'P1-CI', 'Rwanda''s involvement in the DRC was primarily motivated by:', 'A desire to colonise the DRC', 'The need to dismantle Hutu militia camps in eastern Zaire and ensure security', 'UN requests for intervention', 'Economic cooperation agreements', 1, 'See mark scheme for detailed explanation.', 26);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-026', '1.9 Political and Economic Impact; RPF-Led Governments; Continued', 'SL/HL', 'P1-CI', 'The ICC was established partly as a response to:', 'World War I', 'The failures of international justice in Rwanda and Yugoslavia', 'The Cold War', 'European colonial expansion', 1, 'See mark scheme for detailed explanation.', 27);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-027', '2.1 Ethnic Tensions Between Serbs and Kosovar Albanians', 'SL/HL', 'P1-CI', 'The 1974 Yugoslav Constitution was significant for Kosovo because it:', 'Abolished Kosovo as a political entity', 'Granted Kosovo significant autonomy within Yugoslavia', 'Made Kosovo an independent state', 'Gave Serbs complete control over Kosovo', 1, 'See mark scheme for detailed explanation.', 28);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-028', '2.1 Ethnic Tensions Between Serbs and Kosovar Albanians', 'SL/HL', 'P1-CI', 'The Battle of Kosovo (1389) was important in the context of the 1990s conflict because:', 'It was the immediate cause of the war', 'It was central to Serbian national mythology and used to justify claims to Kosovo', 'Albanian nationalists used it to claim independence', 'It was irrelevant to modern politics', 1, 'See mark scheme for detailed explanation.', 29);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-029', '2.2 Political Causes: Constitutional Reforms (1989--94); Repression', 'SL/HL', 'P1-CI', 'Milosevic revoked Kosovo''s autonomy in 1989 primarily to:', 'Promote Albanian rights', 'Consolidate his power using Serbian nationalism', 'Comply with international demands', 'Implement democratic reforms', 1, 'See mark scheme for detailed explanation.', 30);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-030', '2.2 Political Causes: Constitutional Reforms (1989--94); Repression', 'SL/HL', 'P1-CI', 'Ibrahim Rugova''s strategy was:', 'Armed resistance against Serbia', 'Peaceful, non-violent resistance and creation of parallel Albanian institutions', 'Alliance with Milosevic', 'Emigration of all Kosovar Albanians', 1, 'See mark scheme for detailed explanation.', 31);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-031', '2.2 Political Causes: Constitutional Reforms (1989--94); Repression', 'SL/HL', 'P1-CI', 'After 1989, Kosovar Albanians experienced:', 'Greater autonomy and freedom', 'Dismissal from public sector jobs, closure of Albanian schools, and systematic repression', 'Democratic elections', 'Economic prosperity', 1, 'See mark scheme for detailed explanation.', 32);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-032', '2.3 Role of Ibrahim Rugova and Non-Violent Resistance', 'SL/HL', 'P1-CI', 'The Dayton Accords (1995) affected Kosovo because:', 'They resolved the Kosovo conflict', 'They ignored Kosovo entirely, disillusioning Kosovar Albanians with peaceful methods', 'They granted Kosovo independence', 'They strengthened Rugova''s position', 1, 'See mark scheme for detailed explanation.', 33);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-033', '2.3 Role of Ibrahim Rugova and Non-Violent Resistance', 'SL/HL', 'P1-CI', 'Rugova''s non-violent strategy ultimately lost support among Kosovar Albanians because:', 'It was too violent', 'Years of peaceful resistance failed to gain meaningful international attention or change on the ground', 'Milosevic agreed to all Albanian demands', 'The UN endorsed violence', 1, 'See mark scheme for detailed explanation.', 34);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-034', '2.4 Kosovo Liberation Army (KLA) and Serbian Response', 'SL/HL', 'P1-CI', 'The KLA gained mass support primarily because:', 'Rugova endorsed armed resistance', 'Serbian disproportionate reprisals against Albanian civilians radicalised the population', 'The UN armed the KLA', 'NATO requested their formation', 1, 'See mark scheme for detailed explanation.', 35);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-035', '2.4 Kosovo Liberation Army (KLA) and Serbian Response', 'SL/HL', 'P1-CI', 'The Drenica massacres (1998) were significant because they:', 'Ended the conflict', 'Drew international attention to Serbian atrocities against Albanian civilians', 'Were carried out by the KLA', 'Had no international impact', 1, 'See mark scheme for detailed explanation.', 36);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-036', '2.5 Ethnic Cleansing and Crimes Against Humanity; Račak Massacre', 'SL/HL', 'P1-CI', 'The Račak massacre (1999) was significant because:', 'It ended the Kosovo conflict', 'It was a key catalyst that led to NATO''s decision to intervene militarily', 'It was carried out by the KLA', 'It had no impact on international policy', 1, 'See mark scheme for detailed explanation.', 37);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-037', '2.5 Ethnic Cleansing and Crimes Against Humanity; Račak Massacre', 'SL/HL', 'P1-CI', 'The Rambouillet negotiations failed because:', 'The Kosovar Albanians refused all terms', 'Serbia refused to accept NATO peacekeepers on its territory', 'NATO refused to participate', 'Both sides agreed immediately', 1, 'See mark scheme for detailed explanation.', 38);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-038', '2.6 Response of the International Community; NATO Bombing; KFOR', 'SL/HL', 'P1-CI', 'NATO''s bombing campaign was controversial because:', 'It was authorised by the UN Security Council', 'It bypassed the UN Security Council, raising questions about its legality under international law', 'Serbia had asked for NATO intervention', 'It lasted only one day', 1, 'See mark scheme for detailed explanation.', 39);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-039', '2.6 Response of the International Community; NATO Bombing; KFOR', 'SL/HL', 'P1-CI', 'Resolution 1244 (1999):', 'Recognised Kosovo''s independence', 'Placed Kosovo under UN administration while maintaining nominal Serbian sovereignty', 'Authorised the genocide', 'Was vetoed by Russia', 1, 'See mark scheme for detailed explanation.', 40);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-040', '2.6 Response of the International Community; NATO Bombing; KFOR', 'SL/HL', 'P1-CI', 'KFOR''s role in Kosovo was to:', 'Support Serbian military operations', 'Maintain security and supervise Serbian withdrawal from Kosovo', 'Carry out the NATO bombing campaign', 'Administer elections in Serbia', 1, 'See mark scheme for detailed explanation.', 41);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-041', '2.7 Social and Economic Consequences; Refugee Crisis; Damage to', 'SL/HL', 'P1-CI', 'The Kosovo refugee crisis involved approximately:', '10,000 displaced people', '100,000 displaced people', 'Nearly 1 million displaced Kosovar Albanians', '5 million displaced people', 2, 'See mark scheme for detailed explanation.', 42);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-042', '2.7 Social and Economic Consequences; Refugee Crisis; Damage to', 'SL/HL', 'P1-CI', 'After the war, Kosovo''s Serbian minority:', 'Remained fully integrated into society', 'Faced revenge attacks and many fled; approximately 200,000 Serbs were displaced', 'Gained political control of Kosovo', 'Were protected by the Serbian army', 1, 'See mark scheme for detailed explanation.', 43);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-043', '2.8 Political Impact in Kosovo; Election of Ibrahim Rugova (2002)', 'SL/HL', 'P1-CI', 'Ibrahim Rugova''s election as president in 2002 was significant because:', 'It led to immediate Kosovo independence', 'It represented a democratic transition and return to Rugova''s peaceful approach', 'Serbia endorsed his presidency', 'It ended the UNMIK mission', 1, 'See mark scheme for detailed explanation.', 44);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-044', '2.8 Political Impact in Kosovo; Election of Ibrahim Rugova (2002)', 'SL/HL', 'P1-CI', 'The ''standards before status'' policy meant:', 'Kosovo would immediately become independent', 'Kosovo had to meet governance standards before its political status would be determined', 'Serbia would decide Kosovo''s future', 'NATO would permanently govern Kosovo', 1, 'See mark scheme for detailed explanation.', 45);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-045', '2.9 ICTY; Indictment of Milosevic; International Reaction', 'SL/HL', 'P1-CI', 'Milosevic''s indictment was historically significant because:', 'He was the first person ever charged with a crime', 'He was the first sitting head of state to be indicted for war crimes by an international tribunal', 'He was immediately convicted', 'The charges were dropped', 1, 'See mark scheme for detailed explanation.', 46);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-046', '2.9 ICTY; Indictment of Milosevic; International Reaction', 'SL/HL', 'P1-CI', 'A key limitation of the ICTY was:', 'It had unlimited funding and time', 'Milosevic died before a verdict was reached, and proceedings were criticised as slow', 'It only prosecuted minor figures', 'It was based in Kosovo', 1, 'See mark scheme for detailed explanation.', 47);

-- Written questions (9 marks)
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-001', '1.1 Ethnic Tensions in Rwanda: Hutu and Tutsi Relations', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the role of ethnic tensions as a cause of the Rwandan genocide.', '• Pre-colonial context: Hutu and Tutsi as social/economic categories; debate over whether they were distinct ethnic groups or class distinctions.
• Colonial impact: Belgian racial policies, identity cards, preferential treatment; hardening of ethnic boundaries.
• Post-independence: Hutu Revolution, anti-Tutsi violence, cycles of exile and return.
• Counter-arguments: ethnicity was manipulated by politicians; economic and political factors also crucial.
• Band 4 (7-9): Nuanced analysis considering both the construction and instrumentalisation of ethnicity.', 2);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-002', '1.2 Creation of the Hutu Power Movement and the Interahamwe', 'SL/HL', 'short_answer', 'P1-CI', 9, 'To what extent was the Rwandan genocide planned in advance?', '• Evidence of planning: creation and arming of Interahamwe, distribution of weapons, Hutu Power propaganda, death lists.
• Role of Akazu and political elite in organising infrastructure of genocide.
• Counter-arguments: some argue it was a spontaneous response to Habyarimana''s assassination; opportunistic local violence.
• Significance of the media (Radio Mille Collines) in coordination.
• Band 4 (7-9): Balanced evaluation with specific evidence for both planned and spontaneous elements.', 3);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-003', '1.3 Role of the Media in Rwanda', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the role of the media in the Rwandan genocide.', '• RTLM: hate broadcasts, target identification, coordination of killings, coded language.
• Kangura: Hutu Ten Commandments, long-term radicalisation.
• Techniques: dehumanisation, fear-mongering, calls to ''self-defence''.
• Effectiveness: reached wide audience in largely illiterate society; radio was trusted medium.
• Counter-argument: media was one factor among many; killings also occurred in areas with limited radio access.
• Band 4 (7-9): Analytical evaluation of media''s role relative to other causes.', 4);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-004', '1.4 Other Causes: Economic Situation and Colonial Legacy', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the importance of economic factors as causes of the Rwandan genocide.', '• Economic crisis: coffee price collapse, SAPs, unemployment, poverty.
• Link to violence: elites scapegoated Tutsis for economic problems; land competition.
• Colonial legacy: economic inequalities rooted in colonial structures.
• Counter-argument: economic factors alone don''t explain genocide; political manipulation and ideology were essential.
• Band 4 (7-9): Balanced analysis weighing economic against political and ethnic factors.', 5);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-005', '1.5 Rwandan Civil War (1990--93) and Assassination of Habyarimana (1994)', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the significance of the Rwandan Civil War (1990--93) and the Arusha Accords as causes of the genocide.', '• Civil War: RPF invasion increased anti-Tutsi sentiment; radicalised Hutu Power movement.
• Arusha Accords: power-sharing threatened Hutu extremists'' grip on power; motivated them to plan genocide as alternative.
• Assassination: immediate trigger; speed of response suggests pre-planning.
• Counter-argument: long-term ethnic tensions and propaganda were more fundamental causes.
• Band 4 (7-9): Clear analysis linking short-term triggers to long-term causes.', 6);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-006', '1.6 Actions of the RPF and Rwandan Government; Nature of the Genocide', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Examine the nature of the Rwandan genocide and the crimes against humanity committed.', '• Scale: 800,000--1,000,000 killed in ~100 days; one of the fastest genocides in history.
• Methods: mass participation, roadblocks, neighbour-on-neighbour violence, churches as killing sites.
• Sexual violence: systematic war rape as deliberate strategy.
• Targeting: both Tutsis and moderate Hutus; political assassination of PM Uwilingiyimana.
• Band 4 (7-9): Detailed, sensitive analysis of the nature and scale of atrocities.', 7);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-007', '1.7 Response of the International Community; UNAMIR; Reasons for', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the response of the international community to the Rwandan genocide.', '• UNAMIR: understaffed, restrictive mandate, Dallaire''s warnings ignored, forces reduced during genocide.
• US: Somalia syndrome, refusal to use ''genocide'', blocked UN action.
• Belgium: withdrawal after peacekeepers killed; fatally weakened UNAMIR.
• France: Opération Turquoise; controversial given prior support for Hutu government.
• Evaluation: catastrophic failure; intervention could have saved hundreds of thousands of lives.
• Band 4 (7-9): Multi-actor analysis with clear evaluation of responsibility and alternatives.', 8);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-008', '1.8 Social Impact: Refugee Crisis; Justice and Reconciliation', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the effectiveness of justice and reconciliation efforts in post-genocide Rwanda.', '• ICTR: convicted senior leaders; established legal precedents; but slow and expensive.
• Gacaca: processed hundreds of thousands of cases; community participation; but concerns about due process.
• Reconciliation: removal of ethnic IDs, emphasis on national unity; but critics argue it suppresses genuine discussion.
• Ongoing challenges: trauma, social divisions, political repression under Kagame.
• Band 4 (7-9): Balanced evaluation of multiple approaches to justice and reconciliation.', 9);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-009', '1.9 Political and Economic Impact; RPF-Led Governments; Continued', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the political and economic impact of the genocide on Rwanda and the wider region.', '• Rwanda: RPF government; political stability but authoritarianism; economic development.
• Regional impact: Congo Wars; destabilisation of DRC; millions of deaths.
• International impact: ICTR established precedents; inspired creation of ICC.
• Long-term: tension between development and human rights; unresolved ethnic issues.
• Band 4 (7-9): Analysis of both domestic and regional consequences with evaluation.', 10);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-010', '2.1 Ethnic Tensions Between Serbs and Kosovar Albanians', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the causes of ethnic tension between Serbs and Kosovar Albanians.', '• Historical: Battle of Kosovo mythology; Ottoman period; different religious and cultural identities.
• Constitutional: 1974 autonomy; demographic shift; competing nationalisms.
• Political: manipulation of ethnic fears by political leaders on both sides.
• Economic: underdevelopment of Kosovo; competition for resources and opportunities.
• Band 4 (7-9): Multi-causal analysis with evaluation of the relative importance of different factors.', 11);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-011', '2.2 Political Causes: Constitutional Reforms (1989--94); Repression', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the role and significance of Slobodan Milosevic in the Kosovo conflict.', '• Rise to power: exploitation of Serbian nationalism; Gazimestan speech.
• Revocation of autonomy: direct cause of escalating Albanian resistance.
• Repression: apartheid-like system; dismissal of Albanians from public life.
• Escalation to war: military operations against KLA; ethnic cleansing campaign.
• Counter-argument: broader Yugoslav dissolution and competing nationalisms also contributed.
• Band 4 (7-9): Nuanced evaluation of Milosevic''s role relative to other factors.', 12);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-012', '2.3 Role of Ibrahim Rugova and Non-Violent Resistance', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the effectiveness of Ibrahim Rugova''s strategy of non-violent resistance in Kosovo.', '• Achievements: maintained Albanian civil society, avoided bloodshed, moral authority.
• Parallel institutions: education, healthcare, governance under repression.
• Limitations: failed to gain international intervention; Dayton Accords bypassed Kosovo.
• Consequence: disillusionment led to rise of KLA and armed resistance.
• Band 4 (7-9): Balanced evaluation considering both achievements and ultimate failure.', 13);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-013', '2.4 Kosovo Liberation Army (KLA) and Serbian Response', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the role of the KLA in the Kosovo conflict.', '• Formation: disillusionment with Rugova''s peaceful approach; Albanian arms crisis.
• Methods: guerrilla warfare; targeted Serbian security forces; civilian casualties on both sides.
• Impact: provoked Serbian military response that drew international attention.
• Controversy: some members accused of war crimes; initially labelled ''terrorists'' by the US.
• Significance: without the KLA, international intervention might not have occurred.
• Band 4 (7-9): Balanced analysis considering both the KLA''s role in provoking intervention and criticisms.', 14);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-014', '2.5 Ethnic Cleansing and Crimes Against Humanity; Račak Massacre', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the significance of the Račak massacre and Rambouillet negotiations for the Kosovo conflict.', '• Račak: 45 civilians killed; Walker declared it a crime against humanity; shocked international community.
• Impact: created political momentum for military intervention.
• Rambouillet: final diplomatic attempt; Serbia''s refusal provided justification for NATO action.
• Controversy: some question the Račak narrative; others argue Rambouillet terms were deliberately unacceptable to Serbia.
• Band 4 (7-9): Analysis of both events with consideration of different interpretations.', 15);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-015', '2.6 Response of the International Community; NATO Bombing; KFOR', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the international community''s response to the Kosovo crisis.', '• Diplomatic efforts: Contact Group, Rambouillet negotiations; failed to reach agreement.
• NATO bombing: bypassed UNSC; effective in ending Serbian operations; but civilian casualties.
• Post-war: KFOR deployment, UNMIK administration; stabilised Kosovo.
• Legal/moral debate: humanitarian intervention vs. sovereignty; precedent for future interventions.
• Band 4 (7-9): Multi-faceted evaluation considering effectiveness, legality, and precedent.', 16);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-016', '2.7 Social and Economic Consequences; Refugee Crisis; Damage to', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Examine the social and economic consequences of the Kosovo conflict.', '• Refugee crisis: ~1 million Albanians displaced; post-war displacement of ~200,000 Serbs.
• Infrastructure: widespread destruction of homes, schools, hospitals.
• Economic impact: already weak economy devastated; high unemployment; aid dependency.
• Social consequences: trauma, ethnic segregation, reverse ethnic cleansing.
• Band 4 (7-9): Comprehensive analysis covering consequences for all affected communities.', 17);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-017', '2.8 Political Impact in Kosovo; Election of Ibrahim Rugova (2002)', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the political impact of the Kosovo conflict on the region.', '• Kosovo: transition from UN administration to self-governance; democratic elections; path to independence.
• Serbia: political upheaval; fall of Milosevic (2000); ongoing dispute over Kosovo.
• Regional: precedent for humanitarian intervention; debate about sovereignty vs. self-determination.
• International: strengthened principle of ''responsibility to protect''; but also concerns about precedent.
• Band 4 (7-9): Analysis of political impact across multiple levels (local, national, international).', 18);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-018', '2.9 ICTY; Indictment of Milosevic; International Reaction', 'SL/HL', 'short_answer', 'P1-CI', 9, 'Evaluate the significance of the ICTY and the indictment of Milosevic for international justice.', '• Precedent: first sitting head of state indicted; demonstrated no one is above international law.
• Achievements: convicted many perpetrators; documented atrocities; contributed to historical record.
• Limitations: Milosevic died before verdict; slow proceedings; perception of ''victor''s justice''.
• Legacy: influenced creation of ICC; raised expectations for accountability.
• Band 4 (7-9): Balanced evaluation of achievements and limitations with clear judgement.', 19);

