INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2.6', 'I can describe the contributions of Luthuli, Sobukwe, and Tutu to the anti-apartheid movement.', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2.6', 'I can compare different approaches within the anti-apartheid movement.', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-rp-cl-2.6', 'I can evaluate the relative significance of key individuals.', 3);

-- Flashcard topics & cards
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-1.1', '1.1 Racism and Violence Against African Americans; the Ku Klux Klan', '#7B9E6B', 'P1-RP', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.1', 'Jim Crow Laws', 'State and local laws enforcing racial segregation in the American South from the 1870s through the 1960s.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.1', 'Ku Klux Klan (KKK)', 'White supremacist organisation using violence, intimidation, and lynching to enforce racial hierarchy and terrorise African Americans.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.1', 'Lynching', 'Extrajudicial murder, often by hanging, of African Americans; used as a tool of racial terror; over 4,000 recorded between 1877 and 1950.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.1', 'Emmett Till (1955)', '14-year-old African American murdered in Mississippi for allegedly whistling at a white woman; his open-casket funeral galvanised the civil rights movement.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.1', 'Plessy v. Ferguson (1896)', 'Supreme Court ruling that ''separate but equal'' facilities were constitutional; legal basis for Jim Crow segregation.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.1', 'White Citizens'' Councils', 'Middle-class white organisations formed after Brown v. Board to resist desegregation through economic pressure and political influence. ☑', 6);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-1.2', '1.2 Disenfranchisement of African Americans', '#7B9E6B', 'P1-RP', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.2', 'Poll taxes', 'Fees required to vote; disproportionately excluded poor African Americans from electoral participation.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.2', 'Literacy tests', 'Tests administered at voter registration; selectively applied to prevent African Americans from voting.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.2', 'Grandfather clause', 'Exempted those whose ancestors could vote before 1867 from literacy tests; effectively allowed white illiterate voters while excluding Black voters.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.2', '15th Amendment (1870)', 'Prohibited denying the vote based on race; systematically undermined in the South through legal and extralegal means.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.2', 'White primary', 'Practice of excluding African Americans from Democratic Party primaries in the one-party South, effectively denying them any political voice. ☑', 5);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-1.3', '1.3 Segregation and Education: Brown v. Board of Education (1954)', '#7B9E6B', 'P1-RP', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.3', 'Chief Justice Earl Warren', 'Led the unanimous Brown decision; argued segregation generated feelings of inferiority in African American children.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.3', 'Brown II (1955)', 'Follow-up ruling ordering desegregation ''with all deliberate speed''; vague wording allowed Southern states to delay.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.3', 'Thurgood Marshall', 'NAACP lawyer who argued Brown v. Board before the Supreme Court; later became the first African American Supreme Court Justice. Kenneth and Mamie Clark doll Psychological experiments showing Black tests children preferred white dolls; used as evidence in Brown that segregation damaged self-esteem.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.3', 'Massive Resistance', 'Southern political strategy of defying school desegregation through legal manoeuvres, school closures, and political pressure. ☑', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-1.4', '1.4 Little Rock Crisis (1957)', '#7B9E6B', 'P1-RP', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.4', 'Little Rock Nine', 'Nine African American students who integrated Central High School in Little Rock, Arkansas, in 1957.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.4', 'Governor Orval Faubus', 'Arkansas governor who used the National Guard to prevent the Little Rock Nine from entering Central High School. President Eisenhower''s Sent 1,200 federal troops (101st intervention Airborne) to Little Rock to enforce desegregation; first use of federal troops for civil rights since Reconstruction.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.4', 'Elizabeth Eckford', 'One of the Little Rock Nine; photographed being harassed by a white mob while walking to school alone. ☑', 3);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-1.5', '1.5 Economic and Social Discrimination; Legacy of Jim Crow Laws', '#7B9E6B', 'P1-RP', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.5', 'Economic inequality', 'African Americans earned significantly less than white Americans; excluded from many professions and unions.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.5', 'Housing discrimination', 'Restrictive covenants, redlining, and discriminatory lending practices confined African Americans to segregated, often impoverished neighbourhoods.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.5', 'Redlining', 'Practice of denying financial services to residents of predominantly Black neighbourhoods; institutionalised housing segregation.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.5', 'Sharecropping', 'Post-slavery agricultural system that kept many Southern African Americans in poverty and economic dependence on white landowners. ☑', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-1.6', '1.6 Non-Violent Protests: Montgomery Bus Boycott (1955--56)', '#7B9E6B', 'P1-RP', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.6', 'Rosa Parks (1 Dec 1955)', 'NAACP member who refused to give up her bus seat in Montgomery, Alabama; her arrest sparked the bus boycott. Montgomery Bus Boycott 381-day boycott of Montgomery buses by (1955--56) African Americans; ended when the Supreme Court ruled bus segregation unconstitutional.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.6', 'Martin Luther King Jr.', 'Baptist minister who emerged as leader of the boycott; adopted Gandhian philosophy of non-violent resistance. Montgomery Improvement Organisation formed to coordinate the Association (MIA) bus boycott; led by MLK.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.6', 'Browder v. Gayle (1956)', 'Federal court ruling (upheld by Supreme Court) that bus segregation was unconstitutional; ended the boycott.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.6', 'E.D. Nixon', 'NAACP leader and labour organiser who helped plan the boycott and selected Rosa Parks''s case as a test case. ☑', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-1.7', '1.7 Freedom Rides (1961)', '#7B9E6B', 'P1-RP', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.7', 'Freedom Rides (May 1961)', 'Interracial groups rode interstate buses through the South to test compliance with desegregation rulings; met with extreme violence. Congress of Racial Equality Civil rights organisation that (CORE) organised the Freedom Rides. Anniston and Birmingham Freedom Riders'' bus was firebombed in attacks Anniston, Alabama; riders were brutally beaten in Birmingham with police complicity. Robert Kennedy''s Attorney General who pressured the ICC intervention to enforce desegregation of interstate bus terminals after the Freedom Rides. Interstate Commerce Banned segregation in interstate bus Commission ruling (1961) terminals; direct result of the Freedom Rides. ☑', 1);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-1.8', '1.8 Freedom Summer (1964)', '#7B9E6B', 'P1-RP', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.8', 'Freedom Summer (1964)', 'Voter registration campaign in Mississippi; brought hundreds of Northern volunteers to the Deep South. Mississippi murders (June Three civil rights workers (Chaney, 1964) Goodman, Schwerner) were murdered by KKK members with police complicity. Mississippi Freedom Alternative political party created to Democratic Party (MFDP) challenge the all-white Mississippi Democratic delegation at the 1964 convention.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.8', 'Fannie Lou Hamer', 'MFDP leader who testified powerfully about voter intimidation at the Democratic National Convention.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.8', 'Freedom Schools', 'Alternative schools established during Freedom Summer to educate and empower African American communities. ☑', 3);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-1.9', '1.9 Legislative Changes: Civil Rights Act (1964)', '#7B9E6B', 'P1-RP', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.9', 'Civil Rights Act (1964)', 'Landmark legislation prohibiting discrimination based on race, colour, religion, sex, or national origin; banned segregation in public facilities.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.9', 'Birmingham Campaign (1963)', 'SCLC-led protests in Birmingham, Alabama; images of police brutality (fire hoses, dogs) shocked the nation and built support for legislation. March on Washington (Aug Massive demonstration of 250,000 1963) people; MLK delivered ''I Have a Dream'' speech; pressured Congress to pass civil rights legislation. President Kennedy''s civil Proposed in June 1963 after Birmingham; rights bill became the basis for the 1964 Civil Rights Act after Kennedy''s assassination. President Johnson and the LBJ used political skill and Kennedy''s Civil Rights Act legacy to push the Civil Rights Act through Congress, including breaking a Senate filibuster. ☑', 2);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-1.10', '1.10 Voting Rights Act (1965)', '#7B9E6B', 'P1-RP', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.10', 'Voting Rights Act (1965)', 'Outlawed discriminatory voting practices (literacy tests, poll taxes); authorised federal oversight of voter registration in the South. Selma to Montgomery marches Three protest marches for voting (1965) rights; ''Bloody Sunday'' on the Edmund Pettus Bridge generated national outrage. Bloody Sunday (7 March Alabama state troopers attacked 1965) peaceful marchers with tear gas and clubs on the Edmund Pettus Bridge in Selma.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.10', '24th Amendment (1964)', 'Abolished poll taxes in federal elections. Impact of the Voting Rights Black voter registration in Mississippi Act rose from 6.7% in 1964 to 59.8% by 1968; transformed Southern politics. ☑', 2);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-1.11', '1.11 Role of Martin Luther King Jr.', '#7B9E6B', 'P1-RP', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.11', 'Non-violent philosophy', 'Influenced by Gandhi and Christian theology; sought to expose injustice through peaceful protest and moral persuasion. Letter from Birmingham Jail MLK''s defence of non-violent direct (1963) action and criticism of white moderates who preferred ''order'' over justice. ''I Have a Dream'' speech Iconic speech at the March on (1963) Washington calling for racial harmony and equality; became a defining moment of the movement. SCLC (Southern Christian Civil rights organisation founded by Leadership Conference) MLK in 1957; coordinated non-violent campaigns across the South. ☑', 1);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-1.12', '1.12 Role of Malcolm X', '#7B9E6B', 'P1-RP', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.12', 'Malcolm X (1925--1965)', 'Influential African American activist; advocate of Black empowerment and self-defence; initially a Nation of Islam minister.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.12', 'Nation of Islam', 'Religious organisation advocating Black separatism, self-reliance, and pride; Malcolm X was its most prominent spokesperson.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.12', '''By any means necessary''', 'Malcolm X''s assertion that African Americans should defend themselves against racial violence; contrasted with MLK''s non-violence. Malcolm X''s pilgrimage to After leaving the Nation of Islam, his Mecca (1964) hajj experience led him to embrace a more inclusive vision of racial justice.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.12', 'Assassination (Feb 1965)', 'Malcolm X was assassinated by Nation of Islam members; his autobiography became hugely influential. ☑', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-1.13', '1.13 Role of Lyndon B. Johnson', '#7B9E6B', 'P1-RP', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.13', 'Johnson''s political skill', 'Master of legislative manoeuvring; used persuasion, deal-making, and Kennedy''s legacy to overcome Southern Democratic opposition. ☑', 1);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-1.14', '1.14 Key Groups: NAACP, SCLC, SNCC, Nation of Islam', '#7B9E6B', 'P1-RP', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.14', 'NAACP', 'Oldest civil rights organisation (founded 1909); focused on legal challenges to segregation; key role in Brown v. Board.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.14', 'SCLC', 'Founded 1957 by MLK; coordinated non-violent campaigns; church-based leadership in the South. SNCC (Student Non-violent Student-led organisation; organised Coordinating Committee) sit-ins, Freedom Rides, voter registration; became more radical by mid-1960s. Nation of Islam (Black Religious movement advocating Black Muslims) separatism and self-reliance; Malcolm X was its most prominent spokesperson.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-1.14', 'Sit-in movement (1960)', 'Student-led sit-ins at segregated lunch counters, beginning in Greensboro, NC; spread to over 70 cities. ☑', 3);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-2.1', '2.1 ''Petty Apartheid'' and ''Grand Apartheid'' Legislation', '#7B9E6B', 'P1-RP', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.1', 'Apartheid', 'System of institutionalised racial segregation in South Africa (1948--1994); enforced white minority rule over the Black majority. National Party victory Afrikaner-dominated party won the (1948) election on a platform of apartheid; began systematic racial legislation.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.1', 'Petty Apartheid', 'Laws enforcing everyday segregation: separate facilities (beaches, buses, benches, hospitals) for different racial groups.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.1', 'Grand Apartheid', 'Large-scale structural segregation: homeland (Bantustan) system, population registration, forced removals. Population Registration Act Classified all South Africans into (1950) racial categories: White, Black, Coloured, Indian; determined every aspect of life.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.1', 'Group Areas Act (1950)', 'Designated specific areas for each racial group; forced millions of non-white people to relocate to designated areas. ☑', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-2.2', '2.2 Division and Classification: Segregation, Townships, Forced Removals', '#7B9E6B', 'P1-RP', 16);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.2', 'Bantustans (Homelands)', 'Designated territories for Black South Africans; intended to strip them of South African citizenship; overcrowded and underdeveloped.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.2', 'Sophiatown removal (1955)', 'Forced removal of Black residents from Sophiatown, a vibrant multiracial suburb of Johannesburg, to Meadowlands (Soweto).', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.2', 'Pass Laws', 'Required Black South Africans to carry ''pass books'' at all times; controlled movement and restricted access to white areas.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.2', 'Bantu Education Act (1953)', 'Established separate, inferior education for Black South Africans; designed to prepare them only for manual labour. Reservation of Separate Legalised segregation of all public Amenities Act (1953) facilities; explicitly stated that facilities did not need to be equal. ☑', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-2.3', '2.3 Protests and Action: The Defiance Campaign and Non-Violent', '#7B9E6B', 'P1-RP', 17);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.3', 'Defiance Campaign (1952)', 'ANC-led campaign of non-violent civil disobedience against apartheid laws; 8,500 arrested; membership grew from 20,000 to 100,000.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.3', 'Freedom Charter (1955)', 'Adopted at the Congress of the People; declared South Africa belongs to all who live in it; vision for a non-racial democratic South Africa. Congress of the People Multi-racial gathering at Kliptown that (1955) adopted the Freedom Charter; included ANC, Indian Congress, Coloured People''s Congress.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.3', 'Women''s March (1956)', '20,000 women of all races marched to the Union Buildings in Pretoria to protest the extension of pass laws to women.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.3', 'Treason Trial (1956--61)', '156 anti-apartheid activists (including Mandela) charged with treason; all eventually acquitted; demonstrated government repression. ☑', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-2.4', '2.4 Sharpeville Massacre (1960) and the Turn to Armed Struggle', '#7B9E6B', 'P1-RP', 18);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.4', 'State of Emergency (1960)', 'Government declared after Sharpeville; ANC and PAC were banned; thousands arrested.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.4', 'Umkhonto we Sizwe (MK)', 'Armed wing of the ANC (''Spear of the Nation''), founded 1961; began sabotage campaign against government infrastructure.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.4', 'Turn to armed struggle', 'After Sharpeville and the banning of the ANC, Mandela and others concluded that non-violence alone could not defeat apartheid. ☑', 3);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-2.5', '2.5 Nelson Mandela and the Rivonia Trial (1963--64)', '#7B9E6B', 'P1-RP', 19);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.5', 'Nelson Mandela (1918--2013)', 'ANC leader; co-founded MK; imprisoned 1964--1990; first democratically elected president of South Africa (1994).', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.5', 'Rivonia Trial (1963--64)', 'Trial of MK leaders including Mandela; charged with sabotage and conspiracy; Mandela sentenced to life imprisonment. Mandela''s speech from the Powerful courtroom speech declaring his dock commitment to a democratic, free society and his willingness to die for this ideal.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.5', 'Robben Island', 'Prison island where Mandela and other political prisoners were held; became a symbol of the anti-apartheid struggle.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.5', 'Impact of Rivonia', 'Decapitated the ANC leadership inside South Africa; but Mandela became an international symbol of resistance. ☑', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-rp-fc-2.6', '2.6 Role of Key Actors: Albert Luthuli, Robert Sobukwe, Desmond Tutu', '#7B9E6B', 'P1-RP', 20);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.6', 'Albert Luthuli', 'ANC President (1952--1967); advocate of non-violent resistance; first African Nobel Peace Prize laureate (1960).', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.6', 'Robert Sobukwe', 'Founder and leader of the PAC; organised the anti-pass campaign that led to Sharpeville; imprisoned and then placed under house arrest.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.6', 'Desmond Tutu', 'Anglican Archbishop; anti-apartheid campaigner who advocated for non-violent resistance and international sanctions; Nobel Peace Prize (1984).', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-rp-fc-2.6', 'Oliver Tambo', 'ANC leader who led the organisation in exile after the bannings; maintained international pressure on the apartheid government. ☑', 4);

-- MCQ questions
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-047', '1.1 Racism and Violence Against African Americans; the Ku Klux Klan', 'SL/HL', 'P1-RP', 'Plessy v. Ferguson (1896) established the principle of:', 'Racial equality under the law', '''Separate but equal'' as constitutional', 'Universal suffrage for all races', 'Federal protection against lynching', 1, 'See mark scheme for detailed explanation.', 48);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-048', '1.1 Racism and Violence Against African Americans; the Ku Klux Klan', 'SL/HL', 'P1-RP', 'The Emmett Till case (1955) was significant because:', 'It led to the immediate passage of civil rights legislation', 'His open-casket funeral exposed the brutality of racial violence and galvanised the movement', 'His murderers were convicted and jailed', 'It ended KKK violence in the South', 1, 'See mark scheme for detailed explanation.', 49);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-049', '1.1 Racism and Violence Against African Americans; the Ku Klux Klan', 'SL/HL', 'P1-RP', 'White Citizens'' Councils differed from the KKK primarily in that they:', 'Supported civil rights', 'Used economic pressure and political influence rather than direct violence', 'Were based in the North', 'Were outlawed by the federal government', 1, 'See mark scheme for detailed explanation.', 50);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-050', '1.1 Racism and Violence Against African Americans; the Ku Klux Klan', 'SL/HL', 'P1-RP', 'Jim Crow laws enforced:', 'Equal rights for all citizens', 'Racial segregation in the American South', 'Northern industrial labour standards', 'Federal civil rights protections', 1, 'See mark scheme for detailed explanation.', 51);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-051', '1.2 Disenfranchisement of African Americans', 'SL/HL', 'P1-RP', 'Literacy tests were used to disenfranchise African Americans by:', 'Testing all voters equally', 'Being selectively and unfairly applied to Black voters', 'Providing free education', 'Encouraging voter registration', 1, 'See mark scheme for detailed explanation.', 52);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-052', '1.2 Disenfranchisement of African Americans', 'SL/HL', 'P1-RP', 'The grandfather clause was designed to:', 'Help African Americans vote', 'Allow illiterate white voters to bypass literacy tests while excluding Black voters', 'Extend voting rights to immigrants', 'Reform the electoral system', 1, 'See mark scheme for detailed explanation.', 53);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-053', '1.3 Segregation and Education: Brown v. Board of Education (1954)', 'SL/HL', 'P1-RP', 'Brown v. Board of Education (1954) was significant because:', 'It upheld Plessy v. Ferguson', 'It ruled that segregated schools were inherently unequal, overturning ''separate but equal''', 'It ended all forms of racial discrimination immediately', 'It was a split decision with limited authority', 1, 'See mark scheme for detailed explanation.', 54);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-054', '1.3 Segregation and Education: Brown v. Board of Education (1954)', 'SL/HL', 'P1-RP', 'Brown II (1955) weakened the impact of Brown I by:', 'Reversing the original decision', 'Ordering desegregation ''with all deliberate speed'', allowing Southern delays', 'Requiring immediate integration of all schools', 'Imposing fines on segregated schools', 1, 'See mark scheme for detailed explanation.', 55);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-055', '1.3 Segregation and Education: Brown v. Board of Education (1954)', 'SL/HL', 'P1-RP', 'The Clark doll tests were used in the Brown case to demonstrate:', 'That African American children were academically superior', 'That segregation damaged the self-esteem and psychological well-being of Black children', 'That white children preferred Black dolls', 'That desegregation would be easy to implement', 1, 'See mark scheme for detailed explanation.', 56);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-056', '1.4 Little Rock Crisis (1957)', 'SL/HL', 'P1-RP', 'Eisenhower sent federal troops to Little Rock to:', 'Support Governor Faubus', 'Enforce the desegregation of Central High School', 'Close the school permanently', 'Arrest the Little Rock Nine', 1, 'See mark scheme for detailed explanation.', 57);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-057', '1.4 Little Rock Crisis (1957)', 'SL/HL', 'P1-RP', 'The Little Rock crisis was significant because:', 'It showed that states could successfully resist federal law', 'It demonstrated federal willingness to enforce desegregation by force', 'It ended school segregation in the South', 'It was widely ignored by the media', 1, 'See mark scheme for detailed explanation.', 58);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-058', '1.5 Economic and Social Discrimination; Legacy of Jim Crow Laws', 'SL/HL', 'P1-RP', 'Redlining was a practice that:', 'Provided loans to African Americans at favourable rates', 'Denied financial services to residents of predominantly Black neighbourhoods', 'Integrated housing in Southern cities', 'Was outlawed by the Plessy v. Ferguson decision', 1, 'See mark scheme for detailed explanation.', 59);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-059', '1.5 Economic and Social Discrimination; Legacy of Jim Crow Laws', 'SL/HL', 'P1-RP', 'The economic impact of Jim Crow laws included:', 'Equal economic opportunities for all races', 'Systematic exclusion of African Americans from well-paying jobs and financial services', 'Rapid economic development in African American communities', 'Federal wealth redistribution programmes', 1, 'See mark scheme for detailed explanation.', 60);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-060', '1.6 Non-Violent Protests: Montgomery Bus Boycott (1955--56)', 'SL/HL', 'P1-RP', 'The Montgomery Bus Boycott lasted approximately:', '30 days', '100 days', '381 days', '2 years', 2, 'See mark scheme for detailed explanation.', 61);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-061', '1.6 Non-Violent Protests: Montgomery Bus Boycott (1955--56)', 'SL/HL', 'P1-RP', 'The boycott ended primarily because:', 'Buses voluntarily desegregated', 'The Supreme Court ruled bus segregation unconstitutional (Browder v. Gayle)', 'Martin Luther King was arrested', 'Montgomery voters passed a desegregation law', 1, 'See mark scheme for detailed explanation.', 62);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-062', '1.6 Non-Violent Protests: Montgomery Bus Boycott (1955--56)', 'SL/HL', 'P1-RP', 'Rosa Parks''s act of defiance was significant because:', 'She was the first person to resist bus segregation', 'Her arrest was used strategically by the NAACP to challenge segregation', 'She used violence to resist', 'It had no lasting impact', 1, 'See mark scheme for detailed explanation.', 63);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-063', '1.6 Non-Violent Protests: Montgomery Bus Boycott (1955--56)', 'SL/HL', 'P1-RP', 'Martin Luther King''s role in the boycott established him as:', 'A local Montgomery politician', 'The national leader of non-violent civil rights protest', 'President of the NAACP', 'A Supreme Court justice', 1, 'See mark scheme for detailed explanation.', 64);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-064', '1.7 Freedom Rides (1961)', 'SL/HL', 'P1-RP', 'The Freedom Rides were organised primarily to:', 'Register voters in the South', 'Test enforcement of desegregation rulings on interstate bus travel', 'Protest the Vietnam War', 'Support President Kennedy''s election', 1, 'See mark scheme for detailed explanation.', 65);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-065', '1.7 Freedom Rides (1961)', 'SL/HL', 'P1-RP', 'The violence against Freedom Riders in Alabama was significant because:', 'It ended the civil rights movement', 'It attracted national media attention and forced federal intervention', 'It showed that segregation was popular nationwide', 'It had no impact on federal policy', 1, 'See mark scheme for detailed explanation.', 66);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-066', '1.8 Freedom Summer (1964)', 'SL/HL', 'P1-RP', 'Freedom Summer (1964) was primarily focused on:', 'Desegregating schools', 'Voter registration in Mississippi', 'Boycotting businesses', 'Integrating the military', 1, 'See mark scheme for detailed explanation.', 67);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-067', '1.8 Freedom Summer (1964)', 'SL/HL', 'P1-RP', 'The murders of Chaney, Goodman, and Schwerner were significant because:', 'They ended the civil rights movement', 'They attracted national attention and increased support for civil rights legislation', 'They went unreported', 'They were committed by federal agents', 1, 'See mark scheme for detailed explanation.', 68);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-068', '1.8 Freedom Summer (1964)', 'SL/HL', 'P1-RP', 'The MFDP challenged the Democratic Party by:', 'Running a Republican candidate', 'Seeking to replace the all-white Mississippi delegation at the national convention', 'Supporting segregationist candidates', 'Withdrawing from politics entirely', 1, 'See mark scheme for detailed explanation.', 69);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-069', '1.9 Legislative Changes: Civil Rights Act (1964)', 'SL/HL', 'P1-RP', 'The Civil Rights Act (1964) primarily:', 'Gave African Americans the right to vote', 'Prohibited discrimination based on race in public facilities and employment', 'Ended poverty in African American communities', 'Established affirmative action quotas', 1, 'See mark scheme for detailed explanation.', 70);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-070', '1.9 Legislative Changes: Civil Rights Act (1964)', 'SL/HL', 'P1-RP', 'The Birmingham Campaign (1963) was crucial for civil rights legislation because:', 'It was entirely peaceful', 'Media coverage of police brutality shocked the nation and built support for legislation', 'It took place in a Northern city', 'President Kennedy led the protests', 1, 'See mark scheme for detailed explanation.', 71);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-071', '1.9 Legislative Changes: Civil Rights Act (1964)', 'SL/HL', 'P1-RP', 'President Johnson was able to pass the Civil Rights Act partly because:', 'He had no political opposition', 'He used Kennedy''s assassination and legacy as political leverage', 'The Act was universally popular', 'The Supreme Court ordered it', 1, 'See mark scheme for detailed explanation.', 72);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-072', '1.10 Voting Rights Act (1965)', 'SL/HL', 'P1-RP', '''Bloody Sunday'' in Selma (1965) directly contributed to:', 'The end of the Vietnam War', 'National support for the Voting Rights Act', 'The election of an African American president', 'The founding of the Black Panther Party', 1, 'See mark scheme for detailed explanation.', 73);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-073', '1.10 Voting Rights Act (1965)', 'SL/HL', 'P1-RP', 'The Voting Rights Act (1965) was significant because:', 'It only applied to Northern states', 'It outlawed discriminatory voting practices and enabled federal oversight of registration', 'It had no measurable impact on voter registration', 'It was vetoed by President Johnson', 1, 'See mark scheme for detailed explanation.', 74);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-074', '1.11 Role of Martin Luther King Jr.', 'SL/HL', 'P1-RP', 'MLK''s philosophy of non-violence was influenced by:', 'Malcolm X and the Nation of Islam', 'Gandhi''s principles of satyagraha and Christian theology', 'Marxist revolutionary theory', 'The Black Panther Party', 1, 'See mark scheme for detailed explanation.', 75);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-075', '1.11 Role of Martin Luther King Jr.', 'SL/HL', 'P1-RP', 'The Letter from Birmingham Jail (1963) argued that:', 'Violence was necessary for change', 'Non-violent direct action was justified and white moderates who prioritised order over justice were part of the problem', 'The civil rights movement should slow down', 'Segregation was acceptable in some circumstances', 1, 'See mark scheme for detailed explanation.', 76);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-076', '1.12 Role of Malcolm X', 'SL/HL', 'P1-RP', 'Malcolm X''s views differed from MLK''s primarily in that Malcolm X:', 'Opposed all forms of protest', 'Advocated Black self-defence and empowerment rather than integration through non-violence', 'Supported segregation for all races', 'Rejected any form of religious belief', 1, 'See mark scheme for detailed explanation.', 77);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-077', '1.12 Role of Malcolm X', 'SL/HL', 'P1-RP', 'After his pilgrimage to Mecca, Malcolm X:', 'Became more radical and separatist', 'Adopted a more inclusive view of racial justice, moving away from strict separatism', 'Rejoined the Nation of Islam', 'Abandoned political activism entirely', 1, 'See mark scheme for detailed explanation.', 78);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-078', '1.13 Role of Lyndon B. Johnson', 'SL/HL', 'P1-RP', 'Johnson''s primary contribution to civil rights was:', 'Leading protest marches in the South', 'Using political skill to pass landmark civil rights and voting rights legislation', 'Founding the SCLC', 'Arguing Brown v. Board before the Supreme Court', 1, 'See mark scheme for detailed explanation.', 79);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-079', '1.14 Key Groups: NAACP, SCLC, SNCC, Nation of Islam', 'SL/HL', 'P1-RP', 'The NAACP''s primary strategy was:', 'Armed resistance', 'Legal challenges through the courts', 'Separatism and self-reliance', 'Economic boycotts only', 1, 'See mark scheme for detailed explanation.', 80);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-080', '1.14 Key Groups: NAACP, SCLC, SNCC, Nation of Islam', 'SL/HL', 'P1-RP', 'SNCC differed from the SCLC primarily in that SNCC was:', 'Opposed to civil rights', 'Student-led and often more willing to take direct action at the grassroots level', 'Only active in Northern cities', 'A legal organisation', 1, 'See mark scheme for detailed explanation.', 81);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-081', '2.1 ''Petty Apartheid'' and ''Grand Apartheid'' Legislation', 'SL/HL', 'P1-RP', 'The Population Registration Act (1950) required:', 'All South Africans to register with a political party', 'Classification of all citizens into racial categories', 'Universal suffrage for all races', 'Equal distribution of land', 1, 'See mark scheme for detailed explanation.', 82);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-082', '2.1 ''Petty Apartheid'' and ''Grand Apartheid'' Legislation', 'SL/HL', 'P1-RP', '''Grand Apartheid'' refers to:', 'Segregation of public facilities', 'Large-scale structural segregation including the homeland/Bantustan system', 'International sanctions against South Africa', 'The anti-apartheid movement', 1, 'See mark scheme for detailed explanation.', 83);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-083', '2.1 ''Petty Apartheid'' and ''Grand Apartheid'' Legislation', 'SL/HL', 'P1-RP', 'The Group Areas Act (1950):', 'Allowed all races to live anywhere', 'Designated specific residential areas for each racial group', 'Created employment equality', 'Was voluntary for all citizens', 1, 'See mark scheme for detailed explanation.', 84);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-084', '2.2 Division and Classification: Segregation, Townships, Forced Removals', 'SL/HL', 'P1-RP', 'The purpose of the Bantustan system was to:', 'Create independent, prosperous Black states', 'Strip Black South Africans of citizenship and deny them political rights in South Africa', 'Integrate all races within South Africa', 'Provide quality education to all citizens', 1, 'See mark scheme for detailed explanation.', 85);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-085', '2.2 Division and Classification: Segregation, Townships, Forced Removals', 'SL/HL', 'P1-RP', 'The Bantu Education Act (1953) was designed to:', 'Provide equal education for all races', 'Prepare Black South Africans only for manual labour and low-skilled work', 'Train future Black political leaders', 'Integrate schools across racial lines', 1, 'See mark scheme for detailed explanation.', 86);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-086', '2.3 Protests and Action: The Defiance Campaign and Non-Violent', 'SL/HL', 'P1-RP', 'The Defiance Campaign (1952) was significant because:', 'It overthrew the apartheid government', 'It was the first major mass civil disobedience campaign against apartheid and dramatically increased ANC membership', 'It was entirely unsuccessful', 'It was organised by the government', 1, 'See mark scheme for detailed explanation.', 87);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-087', '2.3 Protests and Action: The Defiance Campaign and Non-Violent', 'SL/HL', 'P1-RP', 'The Freedom Charter (1955) called for:', 'Continued white minority rule', 'A non-racial, democratic South Africa where the country belongs to all who live in it', 'Armed revolution and communist government', 'Separation of all racial groups into independent states', 1, 'See mark scheme for detailed explanation.', 88);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-088', '2.4 Sharpeville Massacre (1960) and the Turn to Armed Struggle', 'SL/HL', 'P1-RP', 'The Sharpeville Massacre (1960) was a turning point because:', 'It ended apartheid immediately', 'It led to the banning of the ANC and PAC and the adoption of armed struggle', 'It strengthened international support for the apartheid government', 'It was a minor incident with little impact', 1, 'See mark scheme for detailed explanation.', 89);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-089', '2.4 Sharpeville Massacre (1960) and the Turn to Armed Struggle', 'SL/HL', 'P1-RP', 'Umkhonto we Sizwe (MK) was:', 'A peaceful protest organisation', 'The armed wing of the ANC, founded after non-violent methods were deemed insufficient', 'A government security force', 'A trade union', 1, 'See mark scheme for detailed explanation.', 90);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-090', '2.5 Nelson Mandela and the Rivonia Trial (1963--64)', 'SL/HL', 'P1-RP', 'The Rivonia Trial (1963--64) resulted in:', 'The acquittal of all defendants', 'Life imprisonment for Mandela and other MK leaders', 'The end of apartheid', 'International recognition of the South African government', 1, 'See mark scheme for detailed explanation.', 91);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-091', '2.5 Nelson Mandela and the Rivonia Trial (1963--64)', 'SL/HL', 'P1-RP', 'Mandela''s speech from the dock was significant because:', 'He pleaded guilty to all charges', 'He articulated his commitment to democracy and willingness to die for freedom, making him an international symbol', 'He denounced the ANC', 'It was never published', 1, 'See mark scheme for detailed explanation.', 92);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-092', '2.6 Role of Key Actors: Albert Luthuli, Robert Sobukwe, Desmond Tutu', 'SL/HL', 'P1-RP', 'Albert Luthuli is significant because he:', 'Founded the PAC', 'Led the ANC and was the first African to receive the Nobel Peace Prize', 'Organised the Soweto uprising', 'Was the first president of democratic South Africa', 1, 'See mark scheme for detailed explanation.', 93);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-093', '2.6 Role of Key Actors: Albert Luthuli, Robert Sobukwe, Desmond Tutu', 'SL/HL', 'P1-RP', 'Robert Sobukwe differed from ANC leaders primarily in his:', 'Support for apartheid', 'More Africanist ideology and rejection of multi-racial alliances', 'Opposition to all forms of protest', 'Support for white minority rule', 1, 'See mark scheme for detailed explanation.', 94);

-- Written questions (9 marks)
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-019', '1.1 Racism and Violence Against African Americans; the Ku Klux Klan', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Examine the nature and impact of racial discrimination in the United States before the civil rights movement.', '• Legal discrimination: Jim Crow laws, Plessy v. Ferguson, disenfranchisement.
• Violence and terror: KKK, lynching, White Citizens'' Councils.
• Impact on individuals and communities: social, economic, psychological effects.
• Significance of key cases (Emmett Till) in raising awareness.
• Band 4 (7-9): Comprehensive analysis linking legal, social, and violent forms of discrimination.', 20);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-020', '1.2 Disenfranchisement of African Americans', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the effectiveness of methods used to disenfranchise African Americans in the South.', '• Methods: poll taxes, literacy tests, grandfather clauses, white primaries, intimidation.
• Effectiveness: by 1940, only 3% of eligible Black Southerners were registered to vote in some states.
• Legal framework: undermined 15th Amendment while maintaining constitutional appearance.
• Consequences: political powerlessness reinforced social and economic inequality.
• Band 4 (7-9): Detailed analysis of multiple methods with evidence of their cumulative impact.', 21);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-021', '1.3 Segregation and Education: Brown v. Board of Education (1954)', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the significance of Brown v. Board of Education (1954) for the civil rights movement.', '• Legal significance: overturned Plessy v. Ferguson for education; established that segregation was unconstitutional.
• Symbolic significance: demonstrated that the federal judiciary could support civil rights.
• Limitations: Brown II allowed delays; Massive Resistance; actual desegregation was slow.
• Catalyst: inspired further activism (Montgomery, sit-ins); showed legal victories were possible.
• Band 4 (7-9): Balanced evaluation of both significance and limitations.', 22);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-022', '1.4 Little Rock Crisis (1957)', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the significance of the Little Rock crisis (1957) for the civil rights movement.', '• Events: Faubus''s defiance, mob violence, Eisenhower''s deployment of federal troops.
• Significance: federal vs. state authority; media coverage attracted international attention.
• Limitations: integration remained slow; only one of the Nine graduated from Central High.
• Broader impact: demonstrated that Brown could be enforced; emboldened further activism.
• Band 4 (7-9): Analysis of both significance and limitations with specific evidence.', 23);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-023', '1.5 Economic and Social Discrimination; Legacy of Jim Crow Laws', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Examine the nature and impact of economic and social discrimination on African Americans.', '• Economic: lower wages, job exclusion, sharecropping, union discrimination.
• Social: housing segregation, redlining, restricted access to public facilities.
• Cumulative impact: poverty cycle, limited educational opportunities, health disparities.
• Connection to political activism: economic grievances as motivation for protest.
• Band 4 (7-9): Comprehensive analysis linking economic and social dimensions.', 24);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-024', '1.6 Non-Violent Protests: Montgomery Bus Boycott (1955--56)', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the significance of the Montgomery Bus Boycott (1955--56) for the civil rights movement.', '• Immediate impact: first major sustained community-wide Black protest in the South; economic pressure on bus company.
• Leadership: emergence of MLK as national figure; establishment of non-violent philosophy.
• Legal victory: Browder v. Gayle affirmed unconstitutionality of bus segregation.
• Limitations: only desegregated buses; Jim Crow remained in other areas; violence against activists continued.
• Broader significance: inspired future protests; demonstrated effectiveness of mass action and non-violence.
• Band 4 (7-9): Balanced analysis of significance and limitations with specific evidence.', 25);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-025', '1.7 Freedom Rides (1961)', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the effectiveness of the Freedom Rides (1961) in advancing civil rights.', '• Aims: test compliance with desegregation of interstate travel; provoke federal intervention.
• Methods: non-violent direct action; interracial groups challenging segregation.
• Results: violence attracted media attention; ICC ruling desegregated interstate terminals.
• Limitations: did not address broader segregation issues; violence deterred some participation.
• Band 4 (7-9): Clear evaluation of effectiveness with balanced consideration of achievements and limitations.', 26);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-026', '1.8 Freedom Summer (1964)', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the significance of Freedom Summer (1964) for the civil rights movement.', '• Aims and methods: voter registration, Freedom Schools, community organising.
• Violence: murders of civil rights workers; widespread intimidation.
• Political impact: MFDP challenge at Democratic Convention; Fannie Lou Hamer''s testimony.
• Legislative impact: contributed to momentum for Voting Rights Act (1965).
• Limitations: few African Americans actually registered; internal tensions within the movement.
• Band 4 (7-9): Balanced evaluation with clear judgement about overall significance.', 27);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-027', '1.9 Legislative Changes: Civil Rights Act (1964)', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the factors that led to the passage of the Civil Rights Act (1964).', '• Grassroots activism: Birmingham Campaign, March on Washington, years of protests.
• Media impact: television coverage of violence and injustice shifted public opinion.
• Political leadership: Kennedy''s proposal, Johnson''s legislative skill.
• Historical context: Cold War pressure, moral arguments, Kennedy''s assassination.
• Band 4 (7-9): Multi-causal analysis with evaluation of relative importance of factors.', 28);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-028', '1.10 Voting Rights Act (1965)', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the significance of the Voting Rights Act (1965) for African Americans.', '• Context: Selma marches, Bloody Sunday, years of voter registration campaigns.
• Provisions: banned literacy tests, authorised federal oversight, opened elections to African Americans.
• Impact: dramatic increase in Black voter registration and elected officials.
• Limitations: did not address economic inequality; ongoing challenges to voting access.
• Band 4 (7-9): Clear evaluation of significance balanced against remaining challenges.', 29);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-029', '1.11 Role of Martin Luther King Jr.', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the role and significance of Martin Luther King Jr. in the civil rights movement.', '• Leadership: Montgomery, Birmingham, Selma, March on Washington; Nobel Peace Prize.
• Philosophy: non-violence as both moral principle and strategic tool.
• Impact: galvanised support, attracted media attention, influenced legislation.
• Limitations/criticism: accused of being too moderate by some; did not solve economic inequality.
• Historiography: some argue the movement was driven by grassroots activists, not just MLK.
• Band 4 (7-9): Nuanced evaluation considering multiple perspectives on MLK''s role.', 30);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-030', '1.12 Role of Malcolm X', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Compare and contrast the roles of Martin Luther King Jr. and Malcolm X in the civil rights movement.', '• MLK: non-violence, integration, moral persuasion, legal change, Southern focus.
• Malcolm X: self-defence, Black empowerment, separatism (initially), Northern urban focus.
• Both: sought to end racial oppression; influenced by religion; became international figures.
• Significance: each appealed to different constituencies and contributed differently to the movement.
• Band 4 (7-9): Structured comparison with analysis of both similarities and differences.', 31);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-031', '1.13 Role of Lyndon B. Johnson', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the role of Lyndon B. Johnson in advancing civil rights.', '• Legislative achievements: Civil Rights Act (1964), Voting Rights Act (1965), Great Society programmes.
• Political skill: broke Senate filibuster, used Kennedy''s legacy, persuaded reluctant legislators.
• Motivations: genuine commitment? Political calculation? Both?
• Limitations: Vietnam War diverted attention and resources; did not resolve economic inequality.
• Band 4 (7-9): Nuanced evaluation of Johnson''s role with consideration of multiple perspectives.', 32);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-032', '1.14 Key Groups: NAACP, SCLC, SNCC, Nation of Islam', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the relative effectiveness of the key civil rights organisations (NAACP, SCLC, SNCC, Nation of Islam).', '• NAACP: legal victories (Brown v. Board); limited in direct action.
• SCLC: mass campaigns, media strategy, legislative pressure (Birmingham, Selma).
• SNCC: grassroots organising, voter registration, sit-ins; youth energy.
• Nation of Islam: Black pride and empowerment; limited engagement with mainstream civil rights.
• Evaluation: most effective as a collective ecosystem rather than any single organisation.
• Band 4 (7-9): Comparative analysis with clear evaluation of effectiveness.', 33);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-033', '2.1 ''Petty Apartheid'' and ''Grand Apartheid'' Legislation', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Examine the nature of apartheid legislation in South Africa after 1948.', '• Petty Apartheid: everyday segregation of public facilities, social interaction.
• Grand Apartheid: Population Registration Act, Group Areas Act, Bantu Education, homeland system.
• Impact: comprehensive control of every aspect of Black South Africans'' lives.
• Purpose: maintain white minority political and economic power.
• Band 4 (7-9): Clear distinction between types of apartheid with analysis of their cumulative impact.', 34);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-034', '2.2 Division and Classification: Segregation, Townships, Forced Removals', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the impact of the apartheid classification system on Black South Africans.', '• Population Registration Act: racial classification determined every aspect of life.
• Spatial segregation: Group Areas Act, forced removals, Bantustans, townships.
• Movement control: pass laws restricting freedom of movement.
• Education: Bantu Education limited opportunities and perpetuated inequality.
• Impact: systematic dehumanisation, economic exploitation, destruction of communities.
• Band 4 (7-9): Comprehensive analysis of the interconnected impact of classification systems.', 35);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-035', '2.3 Protests and Action: The Defiance Campaign and Non-Violent', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the effectiveness of non-violent resistance against apartheid in South Africa up to 1960.', '• Campaigns: Defiance Campaign, Freedom Charter, Women''s March, bus boycotts.
• Achievements: raised awareness, grew ANC membership, international attention.
• Limitations: government responded with increased repression; apartheid was strengthened, not weakened.
• Significance of the Treason Trial: demonstrated state repression but also resilience of the movement.
• Context: leads to reassessment of strategy after Sharpeville (1960).
• Band 4 (7-9): Balanced evaluation of achievements and limitations of non-violent strategies.', 36);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-036', '2.4 Sharpeville Massacre (1960) and the Turn to Armed Struggle', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the significance of the Sharpeville Massacre (1960) for the anti-apartheid movement.', '• Events: PAC anti-pass protest, police opened fire, 69 killed.
• Immediate consequences: State of Emergency, banning of ANC and PAC.
• Strategic shift: formation of MK, turn to armed struggle.
• International impact: worldwide condemnation, beginning of sanctions movement.
• Long-term significance: radicalisation of the movement; Sharpeville as symbol of apartheid brutality.
• Band 4 (7-9): Analysis of both immediate and long-term significance.', 37);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-037', '2.5 Nelson Mandela and the Rivonia Trial (1963--64)', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the significance of Nelson Mandela for the anti-apartheid movement up to 1964.', '• Early activism: ANC Youth League, Defiance Campaign, Freedom Charter.
• Armed struggle: co-founded MK; strategic decision to adopt sabotage.
• Rivonia Trial: speech from the dock; transformation into international symbol.
• Impact of imprisonment: galvanised international solidarity; ''Free Mandela'' campaign.
• Limitations: imprisonment removed him from active leadership; ANC weakened inside South Africa.
• Band 4 (7-9): Nuanced evaluation of Mandela''s significance with balanced consideration of impact.', 38);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-038', '2.6 Role of Key Actors: Albert Luthuli, Robert Sobukwe, Desmond Tutu', 'SL/HL', 'short_answer', 'P1-RP', 9, 'Evaluate the role and significance of any two key individuals in the anti-apartheid movement.', '• Choose two: Mandela, Luthuli, Sobukwe, Tutu, Tambo.
• For each: describe their approach, key actions, and impact.
• Compare their contributions and assess relative significance.
• Consider different perspectives on their effectiveness.
• Band 4 (7-9): Detailed analysis of chosen individuals with clear comparative evaluation.', 39);

