INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2.5', 'I can describe the Italian invasion of Abyssinia and its causes.', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2.5', 'I can explain the League of Nations'' response and why sanctions failed.', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2.5', 'I can analyse the impact of the Abyssinian crisis on international relations.', 3);
