INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2.6', 'I can explain the significance of Germany''s invasion of Czechoslovakia in March 1939.', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2.6', 'I can describe the Nazi-Soviet Pact and its secret protocols.', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2.6', 'I can analyse why Britain and France declared war over Poland but not Czechoslovakia.', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2.6', 'I can evaluate the significance of the Nazi-Soviet Pact for the outbreak of war.', 4);
