INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2.7', 'I can explain the different reasons for British appeasement.', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2.7', 'I can describe France''s defensive strategy and its limitations.', 2);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2.7', 'I can analyse the failure of collective security against German aggression.', 3);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2.7', 'I can discuss Soviet attempts to form anti-German alliances and why they failed.', 4);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2.7', 'I can evaluate whether a stronger response could have prevented war.', 5);
