INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2.8', 'I can describe the international response to Italy''s invasion of Abyssinia.', 1);
INSERT INTO history_checklist_items (section_id, text, sort_order) VALUES ('hist-p1-mgw-cl-2.8', 'I can explain why League of Nations sanctions were ineffective.', 2);
