-- Flashcard topics & cards
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-mgw-fc-1.1', '1.1 Impact of Japanese Nationalism and Militarism on Foreign Policy', '#8B6B9E', 'P1-MGW', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.1', 'Meiji Restoration (1868)', 'Modernisation of Japan; adoption of Western military technology and imperial ambitions; foundation for future expansionism.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.1', 'Bushido', 'The warrior code of honour that underpinned Japanese military culture and justified sacrifice for the emperor and the nation.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.1', 'Emperor worship (kokutai)', 'The belief in the divinity of the Emperor, used to rally national unity and justify imperial expansion as a sacred duty.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.1', 'Kwantung Army', 'The Japanese military force stationed in Manchuria that acted independently and engineered the Mukden Incident in 1931.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.1', 'Pan-Asianism', 'Ideology promoting Japanese leadership of Asia against Western imperialism; used to justify the Greater East Asia Co-Prosperity Sphere. Cardinal Principles of the Ministry of Education publication National Entity (Kokutai no asserting the Emperor''s divinity and Hongi, 1937) promoting self-sacrifice for the nation; fuelled ultra-nationalism. ☑', 5);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-mgw-fc-1.2', '1.2 Japanese Domestic Issues: Political and Economic Issues', '#8B6B9E', 'P1-MGW', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.2', 'Zaibatsu', 'Powerful Japanese industrial and financial conglomerates (e.g. Mitsui, Mitsubishi) that influenced government policy and benefited from military expansion. Great Depression impact on Collapse of silk exports, mass rural Japan poverty, bank failures (1927 crisis: 25% of banks collapsed); fuelled support for military expansion.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.2', '15 May Incident (1932)', 'Assassination of PM Inukai Tsuyoshi by ultra-nationalist naval officers; effectively ended party government in Japan.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.2', '26 February Incident (1936)', 'Attempted military coup by young army officers; though it failed, it demonstrated military power over civilian politics.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.2', 'Rural-urban divide', 'Rural populations, suffering most from economic hardship, were more conservative and nationalistic; many enlisted in the army, supporting expansionism. ☑', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-mgw-fc-1.3', '1.3 Political Instability in China', '#8B6B9E', 'P1-MGW', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.3', 'Warlord Era (1916--1928)', 'Period following the fall of the Qing Dynasty when regional military leaders controlled different parts of China, creating political fragmentation.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.3', 'Guomindang (GMD/KMT)', 'Chinese Nationalist Party led by Chiang Kai-shek (Jiang Jieshi); sought to unify China but faced communist insurgency and Japanese aggression. Chinese Communist Party Founded 1921; led by Mao Zedong from (CCP) 1935; rival to the GMD, fighting a civil war that weakened China''s ability to resist Japan.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.3', 'Chinese Civil War', 'Conflict between the GMD and CCP that diverted Chinese resources from resisting Japanese expansion and created political instability exploited by Japan.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.3', 'Chiang Kai-shek''s strategy', 'Prioritised fighting the CCP over resisting Japan (''first internal pacification, then external resistance''), which enabled Japanese expansion.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.3', 'Xi''an Incident (1936)', 'Kidnapping of Chiang Kai-shek by Zhang Xueliang, forcing a temporary GMD-CCP alliance (Second United Front) against Japan. ☑', 5);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-mgw-fc-1.4', '1.4 Japanese Invasion of Manchuria and Northern China (1931)', '#8B6B9E', 'P1-MGW', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.4', 'Manchukuo (1932)', 'Japanese puppet state established in Manchuria; nominally led by Puyi, the last Qing emperor, but controlled by Japan.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.4', 'South Manchuria Railway', 'Japanese-controlled railway whose ''sabotage'' was used as justification for the Manchurian invasion.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.4', 'Tanggu Truce (1933)', 'Agreement creating a demilitarised zone south of the Great Wall; effectively recognised Japanese control of Manchuria. Strategic importance of Rich in coal, iron, and agricultural Manchuria resources; seen as vital for Japanese economic self-sufficiency and as a buffer against the Soviet Union. ☑', 3);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-mgw-fc-1.5', '1.5 The Sino-Japanese War (1937--1941)', '#8B6B9E', 'P1-MGW', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.5', 'Rape of Nanjing (Dec 1937)', 'Massacre of an estimated 200,000--300,000 Chinese civilians and POWs by Japanese forces after capturing the Chinese capital.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.5', 'Second United Front (1937)', 'Uneasy alliance between the GMD and CCP to resist Japanese invasion, following the Xi''an Incident. Japanese ''Three Alls'' ''Kill all, burn all, loot all'' -- Policy scorched earth strategy used against Chinese resistance, particularly in rural areas. Chongqing as wartime After Nanjing fell, the GMD relocated capital its capital to Chongqing in southwest China, continuing resistance.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.5', 'Stalemate (1938--1941)', 'After initial rapid advances, the war reached a stalemate as China traded space for time and Japan struggled to control vast territory. ☑', 3);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-mgw-fc-1.6', '1.6 The Tripartite Pact, Pearl Harbor, and the Outbreak of War (1941)', '#8B6B9E', 'P1-MGW', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.6', 'Tripartite Pact (Sept 1940)', 'Alliance between Germany, Italy, and Japan; each recognised the other''s sphere of influence and agreed mutual assistance.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.6', 'Anti-Comintern Pact (1936)', 'Agreement between Japan and Germany (Italy joined 1937) opposing the Communist International; precursor to the Tripartite Pact. Greater East Asia Japanese concept of an Asia-Pacific Co-Prosperity Sphere bloc free from Western imperialism, under Japanese leadership; used to justify expansion. Japanese occupation of Japan moved into French Indochina, Indochina (1940--41) triggering US oil embargo and asset freezing -- critical steps toward Pearl Harbor.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.6', 'Pearl Harbor (7 Dec 1941)', 'Surprise Japanese attack on the US naval base in Hawaii; brought the US into WWII and transformed the conflict into a global war.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.6', 'US oil embargo (1941)', 'After Japan occupied southern Indochina, the US froze Japanese assets and imposed a total trade embargo, cutting 80% of Japan''s oil supply. ☑', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-mgw-fc-1.7', '1.7 League of Nations and the Lytton Report', '#8B6B9E', 'P1-MGW', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.7', 'Lytton Commission (1932)', 'League of Nations investigation into the Manchurian crisis; concluded Japan had acted aggressively but proposed a compromise.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.7', 'Lytton Report findings', 'Acknowledged Japanese interests in Manchuria but concluded the invasion was not justified; recommended Manchuria become an autonomous region under Chinese sovereignty. Japan''s withdrawal from Japan left the League of Nations after League (1933) the Assembly adopted the Lytton Report, demonstrating the League''s inability to enforce its decisions. Failure of collective The Manchurian crisis demonstrated that security the League could not prevent aggression by a major power, setting a precedent for future failures. ☑', 2);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-mgw-fc-1.8', '1.8 The Second United Front', '#8B6B9E', 'P1-MGW', 8);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-mgw-fc-1.9', '1.9 International Response: US Initiatives and US-Japan Tensions', '#8B6B9E', 'P1-MGW', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.9', 'Stimson Doctrine (1932)', 'US policy of non-recognition of territorial changes achieved by force; applied to Manchukuo but had no enforcement mechanism. Quarantine Speech (Oct Roosevelt''s speech calling for the 1937) ''quarantine'' of aggressor nations; signalled a shift from isolationism but produced no immediate action.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.9', 'Panay Incident (Dec 1937)', 'Japanese aircraft sank the USS Panay on the Yangtze River; Japan apologised, but it increased American suspicion.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.9', 'Hull Note (Nov 1941)', 'US demands that Japan withdraw from China and Indochina; seen by Japan as an ultimatum that made war inevitable. US asset freeze and oil After Japan occupied southern embargo (July 1941) Indochina, the US froze Japanese assets and cut off oil supplies, threatening Japan''s ability to wage war.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-1.9', 'Lend-Lease to China (1941)', 'US provided military aid to China under the Lend-Lease programme, further straining US-Japan relations. ☑', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-mgw-fc-2.1', '2.1 Impact of Fascism and Nazism on Foreign Policies of Italy and', '#8B6B9E', 'P1-MGW', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.1', 'Lebensraum', 'Nazi concept of ''living space''; justified German territorial expansion eastward into Poland and the USSR. Mussolini''s foreign policy Restore Roman greatness (spazio aims vitale), create an Italian Mediterranean empire, establish Italy as a great power (Mare Nostrum). Spazio vitale / Mare Italian equivalents of Lebensraum; Nostrum ''vital space'' and ''Our Sea'' -- Mussolini''s vision of Italian dominance in the Mediterranean.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.1', 'Mein Kampf (1925)', 'Hitler''s autobiography outlining his ideological worldview, including anti-Semitism, Lebensraum, and opposition to Versailles. Hitler''s views on the Treaty Saw it as a ''diktat'' and national of Versailles humiliation; reversal of its terms was central to Nazi foreign policy. ☑', 2);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-mgw-fc-2.2', '2.2 Impact of Domestic Economic Issues on Foreign Policies', '#8B6B9E', 'P1-MGW', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.2', 'Autarky', 'Policy of economic self-sufficiency pursued by both Germany and Italy; used to justify territorial expansion for resources.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.2', 'German rearmament', 'Massive military build-up from 1933; violated Versailles but stimulated the economy and prepared for expansionism.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.2', 'Four-Year Plan (1936)', 'Goring''s plan to prepare Germany''s economy for war within four years; focused on autarky and rearmament. Battle for Grain / Battle for Mussolini''s campaigns for agricultural Land (Italy) self-sufficiency; failures contributed to desire for colonial expansion.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.2', 'Mefo Bills', 'Secret financial instruments used to fund German rearmament without appearing in the budget; created by Hjalmar Schacht.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.2', 'Italian corporatism', 'Mussolini''s economic system mixing capitalist and socialist elements; aimed at self-sufficiency but fell short, driving imperial ambitions. ☑', 5);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-mgw-fc-2.3', '2.3 Changing Diplomatic Alignments; End of Collective Security;', '#8B6B9E', 'P1-MGW', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.3', 'Appeasement', 'British and French policy of making concessions to dictators to avoid war; most associated with Neville Chamberlain and the Munich Agreement.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.3', 'Stresa Front (1935)', 'Agreement between Britain, France, and Italy to oppose German violations of Versailles; collapsed over Abyssinian crisis.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.3', 'Rome-Berlin Axis (Oct 1936)', 'Alliance between Mussolini and Hitler; solidified after the Abyssinian crisis pushed Italy away from Britain and France.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.3', 'Anti-Comintern Pact (1936)', 'Agreement between Germany and Japan (Italy joined 1937) against communist expansion; foundation of the Axis alliance. Anglo-German Naval Agreement Britain allowed Germany to build a navy (1935) 35% the size of the Royal Navy; violated Versailles without French consultation.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.3', 'Hoare-Laval Pact (1935)', 'Secret British-French plan to give most of Abyssinia to Italy; leaked and caused public outrage, discrediting appeasement. ☑', 5);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-mgw-fc-2.4', '2.4 German Challenges to the Post-War Settlements (1933--1938)', '#8B6B9E', 'P1-MGW', 13);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.4', 'Sudetenland crisis (1938)', 'Hitler demanded the Sudetenland (German-speaking area of Czechoslovakia); resolved at Munich when Britain and France agreed to cession. Munich Agreement (Sept Britain, France, Germany, and Italy 1938) agreed to cede the Sudetenland to Germany; Chamberlain declared ''peace for our time''. ☑', 1);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-mgw-fc-2.5', '2.5 Italian Expansion: Abyssinia (1935--36), Albania, Entry into WWII', '#8B6B9E', 'P1-MGW', 14);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.5', 'Battle of Adwa (1896)', 'Humiliating Italian defeat by Ethiopia that Mussolini sought to avenge; shaped Italian imperial ambitions. League of Nations sanctions Economic sanctions imposed after the on Italy Abyssinian invasion; excluded oil and were largely ineffective; Suez Canal remained open. Italian annexation of Albania Italy invaded Albania to match German (April 1939) expansion and secure a strategic position in the Balkans. Italy''s entry into WWII Mussolini declared war on France and (June 1940) Britain after Germany''s successful invasion of France, hoping for easy territorial gains.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.5', 'Pact of Steel (May 1939)', 'Military alliance between Germany and Italy; committed both to support each other in war. ☑', 2);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-mgw-fc-2.6', '2.6 German Expansion (1938--39): Pact of Steel, Nazi-Soviet Pact,', '#8B6B9E', 'P1-MGW', 15);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.6', 'Danzig crisis (1939)', 'Hitler demanded the return of Danzig (Gdansk) and a corridor through Polish territory; Poland refused with British support. ☑', 1);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-mgw-fc-2.7', '2.7 International Response to German Aggression (1933--1938)', '#8B6B9E', 'P1-MGW', 16);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.7', 'French defensive strategy', 'France relied on the Maginot Line and alliances; internal political divisions weakened resolve to confront Germany.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.7', 'Maginot Line', 'French defensive fortification along the German border; symbolised France''s defensive mentality and inability to project power. Soviet attempts at collective USSR sought alliances with France and security Britain against Germany; mutual distrust prevented effective cooperation.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.7', 'Franco-Soviet Pact (1935)', 'Mutual assistance pact between France and the USSR; never effectively implemented due to mutual suspicion and lack of military planning. ☑', 3);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-mgw-fc-2.8', '2.8 International Response to Italian Aggression (1935--36)', '#8B6B9E', 'P1-MGW', 17);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.8', 'Hoare-Laval Pact (Dec 1935)', 'Secret plan by Britain and France to give two-thirds of Abyssinia to Italy; leaked, caused scandal, discredited appeasement.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.8', 'League sanctions on Italy', 'Limited economic sanctions imposed Nov 1935; excluded oil, coal, and steel; ineffective in stopping the invasion.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.8', 'Suez Canal issue', 'Britain controlled the Suez Canal but did not close it to Italian shipping, allowing supply of Italian forces in East Africa.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.8', 'Collapse of Stresa Front', 'The Abyssinian crisis and Western sanctions pushed Italy away from Britain and France towards alliance with Germany. ☑', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p1-mgw-fc-2.9', '2.9 International Response to German and Italian Aggression (1940)', '#8B6B9E', 'P1-MGW', 18);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.9', 'Fall of France (June 1940)', 'Germany''s rapid defeat of France left Britain fighting alone against Germany and Italy in Western Europe.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.9', 'Battle of Britain (1940)', 'German air campaign to achieve air superiority over Britain; failure prevented a German invasion (Operation Sea Lion).', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p1-mgw-fc-2.9', 'Churchill''s leadership', 'Replaced Chamberlain as PM in May 1940; rallied British resistance with defiant speeches and refusal to negotiate with Hitler. US Lend-Lease Act (March US provided military aid to Britain and 1941) its allies; crucial for sustaining the war effort before full US entry. Italian failures in North Italian military defeats required Africa and Greece (1940--41) German intervention, overextending Axis resources. ☑', 3);

-- MCQ questions
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-094', '1.1 Impact of Japanese Nationalism and Militarism on Foreign Policy', 'SL/HL', 'P1-MGW', 'Which group engineered the Mukden Incident of 1931?', 'The Imperial Japanese Navy', 'The Kwantung Army', 'The Japanese Diet', 'The Zaibatsu', 1, 'See mark scheme for detailed explanation.', 95);
