INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-096', '1.1 Impact of Japanese Nationalism and Militarism on Foreign Policy', 'SL/HL', 'P1-MGW', 'Pan-Asianism was an ideology that:', 'Promoted Japanese leadership over Asia against Western imperialism', 'Sought to establish democratic governments across Asia', 'Advocated Japan''s withdrawal from all overseas territories', 'Called for equal partnerships between all Asian nations', 0, 'See mark scheme for detailed explanation.', 97);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-097', '1.1 Impact of Japanese Nationalism and Militarism on Foreign Policy', 'SL/HL', 'P1-MGW', 'Which event marked the beginning of Japan''s modern military transformation?', 'The Russo-Japanese War (1904-05)', 'The Meiji Restoration (1868)', 'The Treaty of Shimonoseki (1895)', 'The Washington Naval Conference (1922)', 1, 'See mark scheme for detailed explanation.', 98);
