INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-099', '1.2 Japanese Domestic Issues: Political and Economic Issues', 'SL/HL', 'P1-MGW', 'Japan''s 1927 financial crisis resulted in:', 'The collapse of approximately 25% of banks', 'Japan joining the League of Nations', 'A strengthening of democratic institutions', 'An immediate invasion of China', 0, 'See mark scheme for detailed explanation.', 100);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-100', '1.2 Japanese Domestic Issues: Political and Economic Issues', 'SL/HL', 'P1-MGW', 'The Zaibatsu were:', 'Military officer factions within the Japanese army', 'Powerful industrial and financial conglomerates', 'Political parties supporting democratic reform', 'Secret societies promoting assassination', 1, 'See mark scheme for detailed explanation.', 101);
