INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-106', '1.4 Japanese Invasion of Manchuria and Northern China (1931)', 'SL/HL', 'P1-MGW', 'Manchukuo was:', 'An independent Chinese republic', 'A Soviet-controlled territory', 'A Japanese puppet state headed by Puyi', 'A League of Nations mandated territory', 2, 'See mark scheme for detailed explanation.', 107);
