INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-109', '1.5 The Sino-Japanese War (1937--1941)', 'SL/HL', 'P1-MGW', 'The Rape of Nanjing (1937) involved:', 'A Chinese attack on Japanese civilians', 'Mass atrocities against Chinese civilians and POWs by Japanese forces', 'A successful Chinese defence of their capital', 'A negotiated surrender by China', 1, 'See mark scheme for detailed explanation.', 110);
