INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-119', '1.9 International Response: US Initiatives and US-Japan Tensions', 'SL/HL', 'P1-MGW', 'The Stimson Doctrine (1932) declared that the US would:', 'Militarily intervene against Japan', 'Not recognise territorial changes made by force', 'Impose economic sanctions on Japan', 'Form a military alliance with China', 1, 'See mark scheme for detailed explanation.', 120);
