INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-128', '2.3 Changing Diplomatic Alignments; End of Collective Security;', 'SL/HL', 'P1-MGW', 'The Stresa Front collapsed primarily because:', 'Germany invaded Poland', 'The Abyssinian crisis drove Italy towards Germany', 'The Soviet Union joined the alliance', 'Britain withdrew from Europe entirely', 1, 'See mark scheme for detailed explanation.', 129);
