INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-130', '2.3 Changing Diplomatic Alignments; End of Collective Security;', 'SL/HL', 'P1-MGW', 'The Rome-Berlin Axis (1936) was formed primarily because:', 'Italy and Germany had always been allies', 'The Abyssinian crisis pushed Italy away from Britain and France towards Germany', 'Britain requested the alliance', 'The League of Nations arranged it', 1, 'See mark scheme for detailed explanation.', 131);
