INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-133', '2.4 German Challenges to the Post-War Settlements (1933--1938)', 'SL/HL', 'P1-MGW', 'The Anschluss (1938) was:', 'A military alliance between Germany and Italy', 'Germany''s annexation of Austria', 'A trade agreement between Germany and Britain', 'Germany''s invasion of Poland', 1, 'See mark scheme for detailed explanation.', 134);
