INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-135', '2.5 Italian Expansion: Abyssinia (1935--36), Albania, Entry into WWII', 'SL/HL', 'P1-MGW', 'Mussolini entered WWII in June 1940 because:', 'Britain attacked Italy first', 'He wanted to share in German victory after France''s fall', 'Germany forced Italy to join', 'Italy was attacked by Abyssinia', 1, 'See mark scheme for detailed explanation.', 136);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-136', '2.5 Italian Expansion: Abyssinia (1935--36), Albania, Entry into WWII', 'SL/HL', 'P1-MGW', 'The Pact of Steel (1939) was:', 'An alliance between Britain and France', 'A military alliance between Germany and Italy', 'A trade agreement between Italy and Abyssinia', 'A non-aggression pact between Germany and the USSR', 1, 'See mark scheme for detailed explanation.', 137);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-137', '2.6 German Expansion (1938--39): Pact of Steel, Nazi-Soviet Pact,', 'SL/HL', 'P1-MGW', 'The Nazi-Soviet Pact (1939) was significant because:', 'It created a lasting alliance between Germany and the USSR', 'It removed the threat of a two-front war for Germany and enabled the invasion of Poland', 'It was arranged by the League of Nations', 'It prevented the outbreak of WWII', 1, 'See mark scheme for detailed explanation.', 138);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-138', '2.6 German Expansion (1938--39): Pact of Steel, Nazi-Soviet Pact,', 'SL/HL', 'P1-MGW', 'Germany''s invasion of Czechoslovakia in March 1939 was a turning point because:', 'It was the first German territorial expansion', 'It proved Hitler''s aims went beyond uniting ethnic Germans, ending appeasement', 'It was approved by the Munich Agreement', 'It led to immediate war with Britain', 1, 'See mark scheme for detailed explanation.', 139);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-139', '2.6 German Expansion (1938--39): Pact of Steel, Nazi-Soviet Pact,', 'SL/HL', 'P1-MGW', 'Britain declared war on Germany on 3 September 1939 because:', 'Germany invaded France', 'Germany violated the Munich Agreement', 'Germany invaded Poland, triggering the British guarantee', 'Germany attacked the British navy', 2, 'See mark scheme for detailed explanation.', 140);
