INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-141', '2.7 International Response to German Aggression (1933--1938)', 'SL/HL', 'P1-MGW', 'A key reason Britain pursued appeasement was:', 'Britain wanted to help Germany expand', 'Strong public anti-war sentiment and desire to avoid another world war', 'Britain had no military capability', 'Churchill demanded appeasement', 1, 'See mark scheme for detailed explanation.', 142);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-142', '2.8 International Response to Italian Aggression (1935--36)', 'SL/HL', 'P1-MGW', 'Why were League sanctions against Italy ineffective?', 'They were too harsh and Italy collapsed economically', 'They excluded key commodities like oil, and the Suez Canal remained open', 'The US enforced a strict oil embargo', 'Italy withdrew from Abyssinia immediately', 1, 'See mark scheme for detailed explanation.', 143);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-143', '2.9 International Response to German and Italian Aggression (1940)', 'SL/HL', 'P1-MGW', 'The Fall of France in June 1940 was significant because:', 'It ended WWII', 'It left Britain fighting alone against Germany in Western Europe', 'It strengthened the League of Nations', 'It led to a German-British alliance', 1, 'See mark scheme for detailed explanation.', 144);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p1-mcq-144', '2.9 International Response to German and Italian Aggression (1940)', 'SL/HL', 'P1-MGW', 'The Battle of Britain (1940) was important because:', 'Germany successfully invaded Britain', 'Britain''s survival prevented German domination of Western Europe', 'France was liberated', 'The US declared war on Germany', 1, 'See mark scheme for detailed explanation.', 145);

-- Written questions (9 marks)
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-039', '1.1 Impact of Japanese Nationalism and Militarism on Foreign Policy', 'SL/HL', 'short_answer', 'P1-MGW', 9, 'Examine the role of nationalism and militarism in shaping Japanese foreign policy in the 1930s.', '• Responses should address the rise of ultra-nationalism, including the influence of Bushido, emperor worship, and the kokutai ideology.
• Discussion of the growing power of the military over civilian government (e.g. assassinations of moderate politicians, the 15 May 1932 and 26 February 1936 incidents).
• Link between militarism and expansionist aims: securing resources, strategic territories, and national prestige.
• For top marks: balanced analysis weighing nationalism/militarism against other factors (economic crisis, political instability in China), with specific evidence and historiographical awareness.
• Band 4 (7-9): Focused, analytical response with detailed evidence and evaluation of different perspectives.', 40);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-040', '1.2 Japanese Domestic Issues: Political and Economic Issues', 'SL/HL', 'short_answer', 'P1-MGW', 9, 'To what extent were domestic economic issues responsible for Japan''s increasingly aggressive foreign policy in the 1930s?', '• Address specific economic issues: the 1927 financial crisis, impact of Great Depression on trade-dependent economy, collapse of silk exports, rural poverty.
• Link to foreign policy: economic hardship increased support for military solutions; Manchuria seen as source of resources and markets.
• Consider other factors: nationalism, militarism, political instability in China, weakness of the League of Nations.
• Top marks require a balanced evaluation with a clear judgement, using specific evidence.
• Band 4 (7-9): Sustained analysis with balanced weighing of economic vs. other factors.', 41);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-041', '1.3 Political Instability in China', 'SL/HL', 'short_answer', 'P1-MGW', 9, 'Evaluate the significance of China''s political instability as a factor enabling Japanese expansion in East Asia.', '• Detail the nature of Chinese political instability: warlordism, GMD-CCP civil war, Chiang''s prioritisation of fighting communists.
• Explain how this instability enabled Japan: inability to mount unified resistance, strategic vacuum in Manchuria and northern China.
• Consider the Xi''an Incident and the Second United Front as a response.
• Weigh against other factors: Japanese domestic pressures, militarism, economic ambitions.
• Band 4 (7-9): Clear thesis with detailed evidence and balanced evaluation of multiple factors.', 42);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-042', '1.4 Japanese Invasion of Manchuria and Northern China (1931)', 'SL/HL', 'short_answer', 'P1-MGW', 9, 'Examine the causes and consequences of the Japanese invasion of Manchuria in 1931.', '• Causes: domestic pressures (economic crisis, military ambition), strategic importance of Manchuria, political instability in China, the Mukden Incident as pretext.
• Consequences: establishment of Manchukuo, Tanggu Truce, Japan''s withdrawal from the League of Nations (1933), weakening of collective security.
• Consider short-term and long-term consequences, including emboldening further Japanese expansion.
• Band 4 (7-9): Analytical treatment of both causes and consequences with a clear evaluative framework.', 43);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-043', '1.5 The Sino-Japanese War (1937--1941)', 'SL/HL', 'short_answer', 'P1-MGW', 9, 'Evaluate the impact of the Sino-Japanese War (1937--1941) on both Japan and China.', '• Impact on China: massive civilian casualties (Nanjing), destruction of infrastructure, displacement of millions, weakening of GMD government.
• Impact on Japan: overextension of military resources, increasing international isolation, growing economic strain.
• Role of the Second United Front and its limitations.
• Long-term significance: contributed to Japan''s decision to expand south and confront the US.
• Band 4 (7-9): Balanced analysis of impact on both countries with detailed evidence.', 44);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-044', '1.6 The Tripartite Pact, Pearl Harbor, and the Outbreak of War (1941)', 'SL/HL', 'short_answer', 'P1-MGW', 9, 'To what extent was the attack on Pearl Harbor a logical outcome of the deterioration in US-Japanese relations?', '• Trace the deterioration: Japanese expansion in China, occupation of Indochina, US responses (moral embargo, Lend-Lease to China, asset freezes, oil embargo).
• Japanese perspective: oil embargo as existential threat; southern expansion required neutralising US Pacific Fleet.
• Alternative perspectives: some argue Pearl Harbor was a strategic miscalculation; diplomacy (Hull Note) had not been fully exhausted.
• Consider the role of the Tripartite Pact in escalating tensions.
• Band 4 (7-9): Nuanced evaluation with clear judgement supported by specific evidence.', 45);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-045', '1.7 League of Nations and the Lytton Report', 'SL/HL', 'short_answer', 'P1-MGW', 9, 'Evaluate the effectiveness of the League of Nations'' response to the Manchurian crisis (1931--33).', '• Detail the League''s response: Lytton Commission, report findings, Assembly vote.
• Explain limitations: slow response (18 months), no military enforcement, absence of US, Japan simply withdrew.
• Significance: precedent for future aggression (Italy in Abyssinia, Germany in Rhineland).
• Consider whether the League had any viable alternatives given its structural weaknesses.
• Band 4 (7-9): Evaluative analysis with clear judgement about effectiveness.', 46);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-046', '1.8 The Second United Front', 'SL/HL', 'short_answer', 'P1-MGW', 9, 'To what extent was the Second United Front effective in resisting Japanese expansion?', '• Formation: Xi''an Incident, shared threat of Japanese invasion, Soviet pressure.
• Achievements: symbolic unity, some coordinated resistance, international sympathy.
• Limitations: separate armies, mutual suspicion, limited coordination, both sides building for postwar conflict.
• Collapse: New Fourth Army Incident (1941); both sides increasingly fought each other.
• Band 4 (7-9): Balanced evaluation with clear judgement on effectiveness.', 47);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-047', '1.9 International Response: US Initiatives and US-Japan Tensions', 'SL/HL', 'short_answer', 'P1-MGW', 9, 'Evaluate the role of the United States in responding to Japanese expansion between 1931 and 1941.', '• Early period: Stimson Doctrine (moral condemnation without enforcement), isolationist constraints.
• Middle period: Quarantine Speech, Panay Incident, growing concern but limited action.
• Late period: escalation through trade restrictions, asset freezes, oil embargo, Lend-Lease, Hull Note.
• Evaluate effectiveness: too little too late? Or did US actions provoke Japan into war?
• Band 4 (7-9): Analytical evaluation across the full time period with balanced assessment.', 48);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-048', '2.1 Impact of Fascism and Nazism on Foreign Policies of Italy and', 'SL/HL', 'short_answer', 'P1-MGW', 9, 'Compare and contrast the impact of fascism on the foreign policies of Italy and Germany.', '• Similarities: both sought territorial expansion, national prestige, revision of post-WWI order, used ideology to justify aggression.
• Differences: Hitler''s racial ideology and Lebensraum vs. Mussolini''s Mediterranean/African ambitions; scale and aggression differed.
• Consider how ideology intersected with practical considerations (economics, military capability).
• Band 4 (7-9): Structured comparison with detailed evidence for both countries.', 49);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-049', '2.2 Impact of Domestic Economic Issues on Foreign Policies', 'SL/HL', 'short_answer', 'P1-MGW', 9, 'Evaluate the extent to which domestic economic issues drove the foreign policies of Germany and Italy.', '• Germany: rearmament as economic stimulus, need for resources (autarky), Four-Year Plan, Mefo Bills.
• Italy: economic failures (Battle for Grain), need for resources and prestige, corporatism''s limitations.
• Counter-argument: ideology and political ambitions were equally or more important.
• Band 4 (7-9): Balanced analysis weighing economic factors against ideological and political motivations.', 50);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-050', '2.3 Changing Diplomatic Alignments; End of Collective Security;', 'SL/HL', 'short_answer', 'P1-MGW', 9, 'To what extent was appeasement responsible for the outbreak of war in 1939?', '• Arguments for: emboldened Hitler, sacrificed strategic positions (Czechoslovakia), failed to deter aggression, undermined collective security.
• Arguments against: bought time for rearmament, reflected public anti-war sentiment, alternatives were limited, French military weakness.
• Consider specific examples: Rhineland, Anschluss, Munich, Prague.
• Historiographical perspectives: guilty men thesis vs. revisionist defence of appeasement.
• Band 4 (7-9): Nuanced evaluation with multiple perspectives and a clear judgement.', 51);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-051', '2.4 German Challenges to the Post-War Settlements (1933--1938)', 'SL/HL', 'short_answer', 'P1-MGW', 9, 'Examine the significance of German challenges to the post-war settlements between 1933 and 1938.', '• Chronological analysis: withdrawal from League, conscription, Rhineland, Anschluss, Sudetenland/Munich.
• Pattern of escalation: each unchallenged step emboldened Hitler further.
• International responses: failure to act consistently undermined deterrence.
• Significance: demonstrated the collapse of Versailles, failure of collective security, and the road to war.
• Band 4 (7-9): Clear analytical framework examining significance of each challenge.', 52);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-052', '2.5 Italian Expansion: Abyssinia (1935--36), Albania, Entry into WWII', 'SL/HL', 'short_answer', 'P1-MGW', 9, 'Evaluate the significance of the Abyssinian crisis for international relations in the 1930s.', '• Immediate impact: demonstrated League of Nations'' weakness; sanctions failure.
• Diplomatic realignment: destroyed the Stresa Front; pushed Italy towards Germany (Rome-Berlin Axis).
• Precedent: emboldened Hitler; showed that aggression would not be met with effective collective action.
• Impact on appeasement: reinforced British and French reluctance to confront aggressors.
• Band 4 (7-9): Analysis of both immediate and long-term significance with multiple perspectives.', 53);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-053', '2.6 German Expansion (1938--39): Pact of Steel, Nazi-Soviet Pact,', 'SL/HL', 'short_answer', 'P1-MGW', 9, 'To what extent was the Nazi-Soviet Pact the most important factor in the outbreak of WWII in September 1939?', '• Significance of the Pact: removed risk of two-front war, enabled invasion of Poland, shocked Western powers.
• Other factors: long-term (Versailles grievances, ideology), medium-term (appeasement failures, rearmament), immediate (Danzig crisis, British guarantee to Poland).
• Counter-argument: war was likely regardless -- the Pact determined timing, not inevitability.
• Band 4 (7-9): Clear thesis weighing the Pact against other factors with a convincing evaluation.', 54);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-054', '2.7 International Response to German Aggression (1933--1938)', 'SL/HL', 'short_answer', 'P1-MGW', 9, 'Evaluate the international response to German aggression between 1933 and 1938.', '• British response: appeasement (rationale, key moments, Chamberlain).
• French response: defensive strategy, internal divisions, reliance on Britain.
• League of Nations: ineffective, no enforcement mechanism against a major power.
• Soviet response: attempts at collective security, failure to build trust.
• Evaluation: too little, too late? Could a firmer response have deterred Hitler?
• Band 4 (7-9): Multi-perspective analysis with evaluation of alternative outcomes.', 55);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-055', '2.8 International Response to Italian Aggression (1935--36)', 'SL/HL', 'short_answer', 'P1-MGW', 9, 'Evaluate the consequences of the international response to Italian aggression in Abyssinia.', '• Immediate: sanctions failed to stop invasion; Abyssinia conquered by May 1936.
• Diplomatic: collapse of Stresa Front; Italy driven towards Germany; Rome-Berlin Axis formed.
• Broader impact: discredited League of Nations; emboldened Hitler; undermined collective security.
• Alternative perspectives: some argue sanctions were as strong as politically feasible.
• Band 4 (7-9): Analysis of multiple consequences with clear evaluative framework.', 56);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p1-wq-056', '2.9 International Response to German and Italian Aggression (1940)', 'SL/HL', 'short_answer', 'P1-MGW', 9, 'Evaluate the international response to German and Italian aggression in 1940.', '• British response: continued resistance under Churchill despite France''s fall; Battle of Britain.
• US response: shift from neutrality towards support (Destroyers-for-Bases, Lend-Lease).
• Failures: League defunct, France defeated, most of Europe occupied.
• Significance: 1940 as turning point from appeasement to active resistance.
• Band 4 (7-9): Analysis of responses from multiple actors with evaluation of effectiveness.', 57);
